const a = [
  {"id":3040,"text":"Which of the following is the effect of propylthiouracil on thyroid hormone?","explanation":"Propylthiouracil (PTU) is an antithyroid drug used in the treatment of hyperthyroidism. Its primary mechanism of action involves inhibition of thyroid hormone synthesis.\r\n\r\nSpecifically, PTU exerts its effect on the thyroid gland by inhibiting two key steps in thyroid hormone synthesis:\r\n\r\n1. **Inhibition of oxidation of iodide:** The thyroid gland actively takes up iodide from the bloodstream using the sodium-iodide symporter (NIS) on the apical membrane of thyrocytes. PTU inhibits the enzyme thyroid peroxidase (TPO), which is responsible for the oxidation of iodide to iodine within the thyroid follicular cells. This inhibits the formation of iodine radicals necessary for the synthesis of thyroid hormones.\r\n\r\n2. **Inhibition of coupling of iodine:** After iodine is oxidized, it is attached to tyrosine residues on thyroglobulin, a protein within the colloid of thyroid follicles. PTU further inhibits the enzyme TPO from catalyzing the coupling of iodine residues on thyroglobulin, preventing the formation of T3 and T4 (triiodothyronine and thyroxine).","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 308.","responses":[{"text":"Inactivates thyroglobulin","correct":false,"visible":false},{"text":"Hyper activates Na-I symporter","correct":false,"visible":false},{"text":"Inhibit T3 release from thyroglobulin","correct":false,"visible":false},{"text":"Hypertrophy of thyroid follicles","correct":false,"visible":false},{"text":"Inhibits oxidation of iodide and coupling of iodine","correct":true,"visible":false}]},{"id":3430,"text":"Which of the following secretes androgens?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 956.","responses":[{"text":"Adrenal medulla","correct":false,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Zona reticularis","correct":true,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false}]},{"id":8052,"text":"A 66-year-old woman is complaining of abdominal pain, constipation. In the past, she underwent renal stone surgery. On examination, her blood pressure (BP) is 145/77 mmHg and her pulse is 98 beats/min. Her fasting glucose and kidney function tests are normal but her calcium is found to be elevated at 13.05 mg/dL. What is the most likely cause of her hypercalcemia?","explanation":null,"reference":"FA 2021 pg 352-353","responses":[{"text":"Primary hyperparathyroidism","correct":true,"visible":false},{"text":"Growth hormone excess","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Thiazide diuretics","correct":false,"visible":false},{"text":"Vitamin D intoxication","correct":false,"visible":false}]},{"id":8054,"text":"Students of 2nd-year MBBS are given a slide of the pancreas for study. The endocrine part shows islets of Langerhans with different types of cells. What cells of the pancreas secrete pancreatic polypeptide?","explanation":"Gamma cells are endocrine cells located in the islets of Langerhans of the pancreas that produce pancreatic polypeptide (PP) which regulates pancreatic secretion, gut motility, and appetite, and is associated with diabetes and obesity.","reference":null,"responses":[{"text":"Gamma cells","correct":true,"visible":false},{"text":"Islets of Langerhans","correct":false,"visible":false},{"text":"Beta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false}]},{"id":8064,"text":"A 35-year-old lady presents with complaints of heat intolerance, weight loss, and swelling in front of the neck. She is also found to have bilaterally protruded eyes. What is the most appropriate terminology used for the protruded eyes in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1089.","responses":[{"text":"Lid lag","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false},{"text":"Lateral visionary field defect","correct":false,"visible":false},{"text":"Exophthalmos","correct":true,"visible":false},{"text":"Cretinism","correct":false,"visible":false}]},{"id":8201,"text":"An old lady living alone has locked her room door, but she keeps checking whether the door is locked or not every 5 minutes. Which of the following conditions is she most likely to be suffering from?","explanation":null,"reference":"Le, Tao, and Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed., McGraw-Hill Education, 2021: 586","responses":[{"text":"Delirium","correct":false,"visible":false},{"text":"Auditory hallucinations","correct":false,"visible":false},{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Obsessive-compulsive disorder","correct":true,"visible":false},{"text":"Paranoid delusions","correct":false,"visible":false}]},{"id":8217,"text":"What is the insulin preparation of choice in diabetic ketoacidosis?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 737.","responses":[{"text":"Isophane insulin","correct":false,"visible":false},{"text":"Lente insulin","correct":false,"visible":false},{"text":"Regular insulin","correct":true,"visible":false},{"text":"Glargine","correct":false,"visible":false},{"text":"Miglitol","correct":false,"visible":false}]},{"id":8225,"text":"A young patient comes to the emergency room (ER) with intense thirst and dehydration, a blood sugar of 608 mg/dl, serum osmolarity of 300 mOsmol/kg, and pH of 7.1. He is breathing rapidly and his breath emits a fruity smell. What is the diagnosis based on these findings?","explanation":null,"reference":"Sha, Mizaj Shabil, et al. “Breath Analysis for the In Vivo Detection of Diabetic\r\nKetoacidosis.” ACS Omega, 24 Jan. 2022, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8830064/.","responses":[{"text":"Acute renal failure","correct":false,"visible":false},{"text":"Hyperosmolar hyperglycemic nonketotic coma","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Diabetic neuropathy","correct":false,"visible":false}]},{"id":8234,"text":"A 38-year-old woman presents to the clinic with a history of end-stage renal disease secondary to hypertension. She has undergone dialysis 3 times weekly for the last 5 years and her medical records show progressive elevation of calcium levels over the last year. On physical examination, Body Mass Index (BMI) is 22.5 kg/m², blood pressure (BP) is 145/98 mmHg, and pulse rate is 91 beats/min. Laboratory test results: total calcium= 11.9 mg/dL (8.2-10 .2 mg/dL), phosphorus= 6.7 mg/dL (2.3-4.7 mg/dL), creatinine = 9.3 mg/dL (0.6-1.1 mg/dL), alkaline phosphatase = 1181 U/L (50-120 U/L). What is the most likely cause of her hypercalcemia?","explanation":null,"reference":null,"responses":[{"text":"Parathyroid nodular hyperplasia","correct":false,"visible":false},{"text":"Familial hypocalciuric hypercalcemia","correct":false,"visible":false},{"text":"Malignancy associated hypercalcemia","correct":false,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":true,"visible":false}]},{"id":8235,"text":"Which of the following hormones is secreted in large quantities from the zona fasciculata of the adrenal gland?","explanation":"The adrenal cortex, which is divided into three distinct layers (zona glomerulosa, zona fasciculata, and zona reticularis), produces various hormones. The **zona fasciculata** is responsible for the production and secretion of **cortisol**, a glucocorticoid hormone that plays a critical role in regulating metabolism, immune response, and the body's response to stress.\r\n\r\n***\r\n\r\nEstrogen is primarily produced by the ovaries in females, although it is also produced in smaller quantities by the adrenal glands and adipose tissues.\r\n\r\nAdrenocorticotropic hormone (ACTH) is produced by the anterior pituitary gland and stimulates the adrenal cortex, including the zona fasciculata, to produce cortisol.\r\n\r\nAndrogens, such as testosterone, are primarily produced by the testes in males and to a lesser extent by the adrenal glands in both males and females.\r\n\r\nAldosterone is mainly produced in the zona glomerulosa of the adrenal cortex and plays a key role in regulating electrolyte and fluid balance, particularly sodium and potassium levels.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier; 2020: 966.","responses":[{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Androgen","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false}]},{"id":8243,"text":"A 25-year-old lady presents to the endocrine clinic with complaints of weight loss, excessive sweating, tachycardia, and tremors. She was diagnosed with hyperthyroidism after some laboratory investigations. What is the most appropriate cause of tremors in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1084.","responses":[{"text":"Sympathetic nervous system stimulation","correct":true,"visible":false},{"text":"Increased cardiac output","correct":false,"visible":false},{"text":"Psychological disorder","correct":false,"visible":false},{"text":"Weakness","correct":false,"visible":false},{"text":"Sub cutaneous accumulation of matrix","correct":false,"visible":false}]},{"id":8262,"text":"A 30-year-old woman presents to the clinic with palpitations, weight loss, and excessive sweating for almost 5-6 months. She cannot concentrate on carrying out her daily activities especially looking after her children. Recently, she also developed pain in both eyes and her friend told her that one of her eyes has become more prominent than the other. What is the most likely cause of her condition?","explanation":"The patient's symptoms, including palpitations, weight loss, excessive sweating, inability to concentrate, and prominent eyes, are characteristic of **hyperthyroidism**. Grave's disease is an autoimmune disorder where the immune system produces antibodies that stimulate the thyroid gland to produce excessive amounts of thyroid hormones.\r\n\r\nCommon clinical features of Grave's disease include:\r\n\r\n1. **Palpitations**: Due to an increased heart rate and cardiac output caused by elevated thyroid hormones.\r\n\r\n2. **Weight loss**: Hyperthyroidism increases metabolic rate, leading to unintended weight loss.\r\n\r\n3. **Excessive sweating**: Hyperthyroidism increases sympathetic nervous system activity, leading to increased sweating.\r\n\r\n4. **Inability to concentrate**: Excessive thyroid hormones can affect mental function and cause difficulty in focusing.\r\n\r\n5. **Prominent eyes (exophthalmos)**: Grave's disease can lead to swelling of the tissues behind the eyes, causing the eyes to bulge forward.\r\n\r\nThe combination of these symptoms strongly suggests Grave's disease as the underlying cause of her condition.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1081-1082.","responses":[{"text":"Toxic nodular goiter","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hashimoto’s thyroiditis","correct":false,"visible":false},{"text":"Generalized anxiety disorder","correct":false,"visible":false},{"text":"Grave’s disease","correct":true,"visible":false}]},{"id":8266,"text":"A man, charged with murder, pleaded insanity in a court of law. He was brought before the medical officer for examination. How will the medical officer differentiate between true and feigned insanity?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 408.","responses":[{"text":"In feigned insanity the onset is gradual","correct":false,"visible":false},{"text":"In feigned insanity behavioral disturbances are uniform","correct":false,"visible":false},{"text":"In feigned insanity fatigue does not set in","correct":false,"visible":false},{"text":"In feigned insanity the person appreciates repeated examination","correct":false,"visible":false},{"text":"In feigned insanity peculiar facial expressions are absent","correct":true,"visible":false}]},{"id":8268,"text":"A 35-year-old lady is diagnosed with autoimmune hypothyroidism. Her physician was concerned about thyroid auto-antibodies. Which of the following is the most appropriate antibody to detect the autoimmune thyroid disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1085.","responses":[{"text":"Anti-follicular","correct":false,"visible":false},{"text":"Anti-cytoplasmic","correct":false,"visible":false},{"text":"Anti-nuclear","correct":false,"visible":false},{"text":"Anti-peroxidase","correct":true,"visible":false},{"text":"Anti-membrane","correct":false,"visible":false}]},{"id":8284,"text":"A 26-year-old woman is complaining of an abnormal tingling sensation in her hands and feet. For the last 2 years, a neurologist is treating her for a seizure disorder. On examination, her blood pressure (BP) is 125/77 mmHg and her pulse is 98 beats/min. Her investigations show: calcium = 6.5 (7.5-8.5 mg/dL), phosphate = 4.8 (2.5-4.0 mg/dL). What is the most likely cause of her hypocalcemia?","explanation":null,"reference":null,"responses":[{"text":"Primary hypoparathyroidism","correct":true,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Malabsorption syndrome","correct":false,"visible":false},{"text":"Pseudohypoparathyroidism","correct":false,"visible":false},{"text":"Phenytoin toxicity","correct":false,"visible":false}]},{"id":8420,"text":"A 23-year-old woman, nulliparous, tests positive for anti-thyroid peroxidase antibodies and has symptoms consistent with hypothyroidism including constipation, fatigue, dry skin, and weight gain. Which of these conditions is she most likely to have?","explanation":null,"reference":"Mincer, Dana L., and Ishwarlal Jialal. “Hashimoto Thyroiditis.” StatPearls, StatPearls Publishing, 2023. PubMed, http://www.ncbi.nlm.nih.gov/books/NBK459262/.","responses":[{"text":"Subacute thyroiditis","correct":false,"visible":false},{"text":"Grave disease","correct":false,"visible":false},{"text":"Reidel thyroiditis","correct":false,"visible":false},{"text":"Postpartum thyroiditis","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":true,"visible":false}]},{"id":8435,"text":"A 35-year-old woman undergoes a successful thyroidectomy but develops neck swelling and dyspnea soon after the surgery. What is the next best step in management?","explanation":null,"reference":"openanesthesia. “Thyroidectomy: Complications.” OpenAnesthesia, https://beta.openanesthesia.org/keywords/thyroidectomy_complications/. Accessed 22 Dec. 2023.","responses":[{"text":"Tracheal intubation","correct":false,"visible":false},{"text":"Cricothyrotomy","correct":false,"visible":false},{"text":"Urgent transfer to the operating theatre","correct":true,"visible":false},{"text":"Expectant management","correct":false,"visible":false},{"text":"Emergency tracheostomy","correct":false,"visible":false}]},{"id":8462,"text":"A person diagnosed with type 1 diabetes mellitus develops ketoacidosis. What is the first step in management?","explanation":null,"reference":"Gosmanov, Aidar R., et al. “Management of Adult Diabetic Ketoacidosis.” Diabetes, Metabolic Syndrome and Obesity: Targets and Therapy, 30 June 2014, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4085289/.","responses":[{"text":"IV insulin bolus","correct":true,"visible":false},{"text":"Oral insulin administration","correct":false,"visible":false},{"text":"Oral rehydration","correct":false,"visible":false},{"text":"3 percent saline infusion","correct":false,"visible":false},{"text":"IV dextrose","correct":false,"visible":false}]},{"id":8484,"text":"An asthmatic individual who is on regular therapy for the past year develops symptoms of Cushing's syndrome. What is the most likely etiology?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 171.","responses":[{"text":"Pituitary tumor","correct":false,"visible":false},{"text":"Iatrogenic","correct":true,"visible":false},{"text":"Adrenal tumor","correct":false,"visible":false},{"text":"Idiopathic","correct":false,"visible":false},{"text":"Ectopic ACTH secreting tumor","correct":false,"visible":false}]},{"id":8490,"text":"A 6-year-old child presents with signs and symptoms of adrenal insufficiency. He also has a long history of mucocutaneous candidiasis. What is the most likely diagnosis?","explanation":null,"reference":"Husebye, Eystein S., et al. “Autoimmune Polyendocrine Syndromes.” The New England Journal of Medicine, 22 Mar. 2018, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6007870/.","responses":[{"text":"Congenital adrenal hyperplasia","correct":false,"visible":false},{"text":"Mccune-Albright syndrome","correct":false,"visible":false},{"text":"Autoimmune polyendocrinopathy","correct":true,"visible":false},{"text":"Post-tuberculosis adrenalitis","correct":false,"visible":false},{"text":"MEN-1 syndrome","correct":false,"visible":false}]},{"id":8605,"text":"A 7-year-old boy comes to the clinic for evaluation of short stature. He is shorter than his peers. His bone age is 4 years and his height is equivalent to that in a 5-year-old child(3rd percentile). No chronic diseases run in the family. Laboratory investigations reveal no abnormal findings. What is the most likely reason for his short stature?","explanation":null,"reference":"Barstow, Craig, and Caitlyn Rerucha. “Evaluation of Short and Tall Stature in Children.” American Family Physician, vol. 92, no. 1, July 2015, pp. 43–50. www.aafp.org, https://www.aafp.org/pubs/afp/issues/2015/0701/p43.html.","responses":[{"text":"Familial short stature","correct":false,"visible":false},{"text":"Dwarfism","correct":false,"visible":false},{"text":"Constitutional growth delay","correct":true,"visible":false},{"text":"Down syndrome","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false}]},{"id":8624,"text":"What is the mechanism of action of propylthiouracil (PTU)?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 308.","responses":[{"text":"Promotes iodination and coupling","correct":false,"visible":false},{"text":"Irreversible inhibition of acetylcholinesterase","correct":false,"visible":false},{"text":"Inhibits iodination and coupling","correct":true,"visible":false},{"text":"Reversible inhibition of acetylcholinesterase","correct":false,"visible":false},{"text":"Depression of inhibitory pathways (GABA)","correct":false,"visible":false}]},{"id":8656,"text":"What is the marked macrovascular complication of type 2 diabetes mellitus?","explanation":"Type 2 diabetes mellitus is a metabolic disorder characterized by insulin resistance and impaired insulin secretion. It can lead to various complications, both microvascular and macrovascular, due to the chronic hyperglycemia and associated metabolic disturbances.\r\n\r\n**Macrovascular complications** involve large blood vessels and are major contributors to morbidity and mortality in individuals with type 2 diabetes. **Accelerated atherosclerosis** is a significant macrovascular complication observed in diabetes. Atherosclerosis is the buildup of fatty plaques in the arterial walls, leading to narrowing and hardening of the blood vessels.\r\n\r\nIn patients with type 2 diabetes, chronic high blood glucose levels can damage blood vessels and promote the development of atherosclerosis at an accelerated rate. This increases the risk of **coronary artery disease**, **stroke**, and **peripheral vascular disease**.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1107.","responses":[{"text":"Diminishing vision","correct":false,"visible":false},{"text":"Accelerated arthritis","correct":false,"visible":false},{"text":"Tunnel vision","correct":false,"visible":false},{"text":"Retinal vein occlusion","correct":false,"visible":false},{"text":"Accelerated atherosclerosis","correct":true,"visible":false}]},{"id":8666,"text":"A 45-year-old female presented with a nodule in her thyroid region. What is the most common thyroid carcinoma in this age group?","explanation":null,"reference":"Kumar, Vinay, et al. Robbins and Cotran Pathologic Basis of Disease. 9th ed., Elsevier Saunders, 2015: 1100.","responses":[{"text":"Hürthle cell tumor","correct":false,"visible":false},{"text":"Anaplastic carcinoma","correct":false,"visible":false},{"text":"Papillary carcinoma","correct":true,"visible":false},{"text":"Follicular carcinoma","correct":false,"visible":false},{"text":"Medullary cell carcinoma","correct":false,"visible":false}]},{"id":8673,"text":"What is the most common source of ectopic adrenocorticotropic hormone (ACTH) production?","explanation":null,"reference":"(1) Ectopic corticotropin production - An Overview | ScienceDirect topics. Accessed December 14, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/ectopic-corticotropin-production\r\n\r\n(2) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1123.","responses":[{"text":"Small cell lung carcinoma","correct":true,"visible":false},{"text":"Bronchial carcinoid","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false}]},{"id":10322,"text":"A 54-year-old, married woman para-2 comes to the clinic with the complaint of weight gain and lethargy for the past 3 months. She had her last menstrual period 6 years back. Her blood pressure is 150/90 mmHg, her pulse is 65/min, and is regular bilaterally. Her body mass index (BMI) falls in the obese range. Her eyes are puffy, she complains of breathlessness, and cold intolerance, her skin is coarse and her abdomen has white striations present. What is the best diagnostic test for this woman?","explanation":"The best diagnostic test for this 54-year-old woman is **serum TSH level**. Her clinical presentation is highly suggestive of hypothyroidism. The symptoms of weight gain, lethargy, cold intolerance, puffy eyes, and coarse skin are typical features of hypothyroidism. Additionally, her blood pressure is elevated, which can be seen in hypothyroidism.\r\n\r\nIn this case, measuring the serum TSH level is crucial because an elevated TSH level along with low levels of thyroid hormones (T3 and T4) would confirm the diagnosis of primary hypothyroidism. Primary hypothyroidism is the most common cause of hypothyroidism and is characterized by inadequate thyroid hormone production due to dysfunction of the thyroid gland itself.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1086.","responses":[{"text":"Serum cortisol and TSH","correct":false,"visible":false},{"text":"Serum TSH level","correct":true,"visible":false},{"text":"Oral glucose tolerance test","correct":false,"visible":false},{"text":"Oral glucose tolerance test and TSH","correct":false,"visible":false},{"text":"Serum cortisol","correct":false,"visible":false}]},{"id":10350,"text":"A man is brought to the district hospital after being bitten by a snake on foot. He complained of localized pain and swelling of the foot. He then started bleeding through his mouth and nose. On examination, petechial hemorrhage could be seen under his skin. He got bitten by which type of snake?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 529.","responses":[{"text":"Kraits","correct":false,"visible":false},{"text":"Viper","correct":true,"visible":false},{"text":"Cobra","correct":false,"visible":false},{"text":"Elapids","correct":false,"visible":false},{"text":"Sea snake","correct":false,"visible":false}]},{"id":10351,"text":"A young boy is brought to the hospital in a state of shock and fright after being bitten by a cobra on hand. What is the next step of management after reassuring the patient?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 529.","responses":[{"text":"Wash the wound with soap and water","correct":false,"visible":false},{"text":"Suck the wound","correct":false,"visible":false},{"text":"Cut the wound open","correct":false,"visible":false},{"text":"Immobilize the bitten limb","correct":true,"visible":false},{"text":"Tie ligature around the wound","correct":false,"visible":false}]},{"id":10372,"text":"A 25-year-old lactating female comes to the office with a painful swelling on her left breast for the last 5 days and fever for the last 2 days. The swelling has enlarged progressively with increasing pain. On examination, the swelling is located in the left upper quadrant, is erythematous, soft, and tender. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1046.","responses":[{"text":"Abscess","correct":true,"visible":false},{"text":"Phyllodes tumor","correct":false,"visible":false},{"text":"Carcinoma","correct":false,"visible":false},{"text":"Fibroadenoma","correct":false,"visible":false},{"text":"Cyst","correct":false,"visible":false}]},{"id":10385,"text":"An infant presents to the outpatient department with complaints of lethargy, difficulty in feeding, and constipation for the past 1 month. On examination, the baby has a protruded tongue, husky cry, and an umbilical hernia. Laboratory results show an increased level of TSH and reduced levels of free T4. What is the most likely diagnosis?","explanation":null,"reference":"Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 455.","responses":[{"text":"Mucopolysaccharidosis","correct":false,"visible":false},{"text":"Sepsis","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Primary hypothyroidism","correct":true,"visible":false},{"text":"Secondary hypothyroidism","correct":false,"visible":false}]},{"id":10386,"text":"An 11-year-old girl has a short stature and increased weight. She also complains of cold intolerance and increased sleep. Her bone age is delayed. Lab results show an increased level of TSH and a reduced free T4. What is the most likely diagnosis?","explanation":null,"reference":"Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 454.","responses":[{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Congenital hyperthyroidism","correct":false,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"Acquired hypothyroidism","correct":true,"visible":false},{"text":"Congenital hypothyroidism","correct":false,"visible":false}]},{"id":11131,"text":"Which of the following hormones does not use cyclic adenosine monophosphate (cAMP) as a second messenger?","explanation":"**Estrogen** is the hormone that does not use **cyclic adenosine monophosphate (cAMP)** as a second messenger.\r\n\r\nHormones that use cAMP as a second messenger belong to the class of **peptide hormones or protein hormones**. When these hormones bind to their specific receptors on the cell surface, it activates the receptor, leading to the generation of cAMP inside the cell. cAMP then acts as a second messenger, activating protein kinases and initiating various intracellular signaling cascades.\r\n\r\nHowever, **estrogen** is a **steroid hormone**, and it uses a different mechanism for signal transduction. Steroid hormones like estrogen are lipophilic and can cross the cell membrane to bind to intracellular receptors located in the cytoplasm or nucleus. This hormone-receptor complex then directly interacts with specific DNA sequences, regulating gene expression and protein synthesis within the target cells.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Estrogen","correct":true,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false}]},{"id":12789,"text":"Which part of the anterior pituitary secretes most of the hormones?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 417-419.","responses":[{"text":"Pars distalis","correct":true,"visible":false},{"text":"Pars tuberalis","correct":false,"visible":false},{"text":"Pars nervosa","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false}]},{"id":12793,"text":"A 28-year-old woman presents to the endocrine clinic with secondary amenorrhea and galactorrhoea for the last 6 months. Her general physical and systemic examination is normal. Lab investigations reveal, prolactin = 3250 mU/L (60–620), free T4 = 15.5 pmol/L (11.5–22.7), thyroid-stimulating hormone (TSH) = 2.5 mU/L (0.35–5.5), and urine pregnancy test is negative. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 683.","responses":[{"text":"Grave disease","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false},{"text":"Primary hypothyroidism","correct":false,"visible":false},{"text":"Cushing's syndrome","correct":false,"visible":false},{"text":"Hypopituitarism","correct":false,"visible":false}]},{"id":13229,"text":"A 33-year-old mother of two children comes with a history of amenorrhea for 6 months. She is negative about pregnancy. For some days she is also experiencing increased milk production from her breasts along with a persistent headache. She also complains of visual disturbances. An optometrist finds her lateral vision reduced. On examination, she is afebrile and nonhypertensive. Which of the following laboratory findings is most likely to be present in this patient?","explanation":"A **prolactinoma** is a benign tumor of the pituitary gland that produces excessive amounts of prolactin, the hormone responsible for milk production. Elevated prolactin levels can lead to amenorrhea, galactorrhea, and visual disturbances due to pressure on the optic nerves.\r\n\r\n***\r\n\r\nWhile hyponatremia can be seen in certain conditions, such as inappropriate antidiuretic hormone (ADH) secretion, it is not the most likely laboratory finding in this case, given the patient's symptoms and presentation.\r\n\r\nGrowth hormone deficiency does not explain her symptoms, including headache, visual disturbances, and galactorrhea.\r\n\r\nElevated serum cholesterol levels can be associated with various metabolic disorders, but they are not typically a prominent feature of prolactinoma. The patient's specific symptoms are better explained by hyperprolactinemia.\r\n\r\nIncreased serum alkaline phosphatase levels are more commonly associated with liver or bone disorders and are not the primary concern in this case.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1079.","responses":[{"text":"Hyponatremia","correct":false,"visible":false},{"text":"Increased serum alkaline phosphatase","correct":false,"visible":false},{"text":"Lack of growth hormone secretion","correct":false,"visible":false},{"text":"Increased serum cholesterol","correct":false,"visible":false},{"text":"Hyperprolactinemia","correct":true,"visible":false}]},{"id":13230,"text":"A 29-year-old primigravida with no prenatal care comes to the emergency department with vaginal bleeding after the onset of labor at 38 weeks, C-section for a lacerated low-lying placenta was performed. She remained hypotensive post-operatively for about 6 hours and was transfused with 12 units of packed RBCs. Now she is unable to feed her newborn and a normal menstrual cycle was not restored. Laboratory findings are hyponatremia, hypokalemia, and hypoglycemia. Which of the following pathological lesion is she most likely to have?","explanation":"**Sheehan syndrome** is a rare but serious condition that occurs due to severe postpartum hemorrhage, resulting in insufficient blood supply to the pituitary gland. This lack of blood supply can lead to pituitary necrosis or damage. The pituitary gland plays a crucial role in regulating various hormones, including those involved in lactation, menstruation, and the body's response to stress.\r\n\r\n\r\n***\r\n\r\nBilateral adrenal hemorrhage would primarily affect adrenal gland function but would not explain the inability to breastfeed, abnormal menstrual cycles, and the combination of hyponatremia, hypokalemia, and hypoglycemia.\r\n\r\nMetastatic choriocarcinoma typically presents with abnormal vaginal bleeding, but it does not explain the pituitary dysfunction, electrolyte abnormalities, and hypoglycemia seen in this case.\r\n\r\nSubacute thyroiditis can lead to thyroid dysfunction but does not account for multiple hormonal deficiencies, electrolyte imbalances, or pituitary involvement.\r\n\r\nInsulitis is inflammation of the pancreatic islets and is related to diabetes mellitus. It would not explain the combination of symptoms seen in this case, particularly the pituitary dysfunction.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015. 1081.","responses":[{"text":"Insulitis","correct":false,"visible":false},{"text":"Bilateral adrenal hemorrhage","correct":false,"visible":false},{"text":"Subacute thyroiditis","correct":false,"visible":false},{"text":"Metastatic choriocarcinoma","correct":false,"visible":false},{"text":"Pituitary necrosis","correct":true,"visible":false}]},{"id":13232,"text":"A 49-year-old female experienced multiple attacks of abdominal pain last year. Three times she had passed stones in the urine during these episodes of pain. Now she is experiencing pain in her right middle finger for one month. On physical examination, her finger is tender. Laboratory reports show calcium 13.7 mg/ dL, phosphate 1.9 mg/ dL, and Creatinine 1.1mg/ dL, albumin 4.8 mg/ dL. Which of the following bone lesions is she most likely to have?","explanation":"**Osteitis Fibrosa Cystica** is a bone disorder commonly associated with **primary hyperparathyroidism**. In this condition, there is excessive secretion of parathyroid hormone (PTH) by the parathyroid glands, leading to increased bone resorption, elevated serum calcium levels (hypercalcemia), and decreased serum phosphate levels (hypophosphatemia).\r\n\r\nThe increased bone resorption causes the formation of **cysts** within the bones and fibrous tissue replacement, leading to weakened and tender bones. This can result in bone pain and deformities. The elevated serum calcium levels can lead to the formation of urinary stones (nephrolithiasis).\r\n\r\nThe laboratory findings of elevated calcium and phosphate levels, along with the clinical presentation of bone pain and previous episodes of urinary stones, support the diagnosis of **Osteitis Fibrosa Cystica** in this patient.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1103.","responses":[{"text":"Osteoid","correct":false,"visible":false},{"text":"Osteochondroma","correct":false,"visible":false},{"text":"Osteitis fibrosa cystica","correct":true,"visible":false},{"text":"Osteoma","correct":false,"visible":false},{"text":"Osteomyelitis","correct":false,"visible":false}]},{"id":13267,"text":"What is the mechanism of action of methimazole?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 693, 695.","responses":[{"text":"Inhibit proteolysis of thyroglobulin","correct":false,"visible":false},{"text":"Prevent binding of iodine to thyroglobulin","correct":true,"visible":false},{"text":"Prevention of thyroid hormone release","correct":false,"visible":false},{"text":"Iodine trapping","correct":false,"visible":false},{"text":"Inhibit synthesis of thyroglobulin","correct":false,"visible":false}]},{"id":13274,"text":"Which drug increases insulin sensitivity by increasing peripheral receptors for insulin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 319.","responses":[{"text":"Acarbose","correct":false,"visible":false},{"text":"Pramlinitide","correct":false,"visible":false},{"text":"Glipizide","correct":false,"visible":false},{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Metformin","correct":false,"visible":false}]},{"id":13283,"text":"A 19-year-old girl is brought to the emergency room by her family who reports that she swallowed a liquid poison in a suicide attempt. On examination, she is bradycardic, hypotensive, flaccid, has excessive salivation, and has convulsions and fasciculations. What is the likely cause of poisoning?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:  538.","responses":[{"text":"Barbiturates","correct":false,"visible":false},{"text":"Cocaine","correct":false,"visible":false},{"text":"Organophosphorus","correct":true,"visible":false},{"text":"Benzodiazepines","correct":false,"visible":false},{"text":"Atropine","correct":false,"visible":false}]},{"id":13328,"text":"A 30-year-old female patient, obese, nondiabetic, presented with significant weight gain, easy fatiguability, and lethargy. On examination, she looked pale, obese, and slightly confused. Her blood pressure is 170/90 mmHg, and her pulse rate is 55 beats/min. She was unable to stand from a sitting position without support and her deep tendon reflexes were diminished. With the given scenario, what is the probable diagnosis?","explanation":"**Hypothyroidism**, characterized by an underactive thyroid gland, can lead to a constellation of symptoms such as weight gain, fatigue, and lethargy due to a slowed metabolism. Bradycardia and elevated blood pressure can result from thyroid hormone imbalances and diminished deep tendon reflexes and muscle weakness are neurological manifestations of the condition.\r\n\r\n***\r\n\r\nObesity alone would not explain the combination of symptoms, including bradycardia, pallor, and diminished deep tendon reflexes.\r\n\r\nObstructive sleep apnea (OSA) is characterized by recurrent episodes of upper airway obstruction during sleep, leading to sleep disturbances and daytime fatigue.\r\n\r\nPolycystic ovarian disease (PCOS) is a hormonal disorder that can cause irregular menstrual cycles, ovarian cysts, and features such as hirsutism and acne.\r\n\r\nCushing syndrome is characterized by excessive cortisol production, leading to a variety of symptoms, including weight gain, fatigue, and hypertension. However, the patient's presentation of bradycardia, diminished deep tendon reflexes, and confusion is not typical of Cushing syndrome, making it an unlikely diagnosis.","reference":"Le T, Bhushan V, Qiu C, et al., eds. First Aid for the USMLE Step 1 2023. 33rd ed. McGraw Hill; 2023: 344.","responses":[{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Obesity","correct":false,"visible":false},{"text":"Hypothyroidism","correct":true,"visible":false},{"text":"Polycystic ovarian disease","correct":false,"visible":false},{"text":"Obstructive sleep apnea","correct":false,"visible":false}]},{"id":13551,"text":"An 8-year-old child presents to the clinic with short stature. A growth hormone deficiency is suspected. Which of the following lab values is the most appropriate test to perform in this child?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 682.\r\n\r\n(2) Gillis D, Magiel E, Terespolsky N, Naugolny L, Strich D. Clonidine stimulation test for GH deficiency: a new look at sample timing. Endocrine Practice: Official Journal of the American College of Endocrinology and the American Association of Clinical Endocrinologists. Accessed December 13, 2022. https://pubmed.ncbi.nlm.nih.gov/88610/","responses":[{"text":"Exercise-induced GH levels","correct":false,"visible":false},{"text":"Clonidine stimulation test","correct":true,"visible":false},{"text":"Insulin induced hypoglycemia","correct":false,"visible":false},{"text":"Sleep-induced GH levels","correct":false,"visible":false},{"text":"Random GH levels","correct":false,"visible":false}]},{"id":13553,"text":"A woman taking corticosteroids for chronic interstitial lung disease (ILD) develops moon facies and weakness. Her lung functions have improved over time. What is the most appropriate management?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 671.","responses":[{"text":"Gradually taper off steroids","correct":true,"visible":false},{"text":"Confirm diagnosis of Cushing syndrome","correct":false,"visible":false},{"text":"Adrenalectomy","correct":false,"visible":false},{"text":"Immediately stop steroids","correct":false,"visible":false},{"text":"Give ketoconazole","correct":false,"visible":false}]},{"id":13567,"text":"A patient reports to the psychiatry ward with a firm belief that somebody wants to kill him. What is this type of delusion called?","explanation":null,"reference":"Semple D, Smyth R. Oxford Handbook of Psychiatry. 3rd ed. Oxford University Press; 2013: 101.","responses":[{"text":"Delusion of self-reproach","correct":false,"visible":false},{"text":"Delusion of grandeur","correct":false,"visible":false},{"text":"Paranoid delusion","correct":true,"visible":false},{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Nihilistic delusion","correct":false,"visible":false}]},{"id":13568,"text":"A young male patient is suffering from a delusional belief where he imagines that he is going to be poisoned by his relatives, wife, and son and they will rob his property. What is this type of delusion called?","explanation":null,"reference":"Semple D, Smyth R. Oxford Handbook of Psychiatry. 3rd ed. Oxford University Press; 2013: 101.","responses":[{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Delusion of grandeur","correct":false,"visible":false},{"text":"Delusion of reference","correct":false,"visible":false},{"text":"Delusion of persecution","correct":true,"visible":false},{"text":"Delusion of self-reproach","correct":false,"visible":false}]},{"id":13569,"text":"High calcitonin levels with a nest of polygonal cells and amyloid deposits on cytology is seen in which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 164.","responses":[{"text":"Thyroid adenoma","correct":false,"visible":false},{"text":"Papillary thyroid carcinoma","correct":false,"visible":false},{"text":"Anaplastic thyroid carcinoma","correct":false,"visible":false},{"text":"Follicular thyroid carcinoma","correct":false,"visible":false},{"text":"Medullary thyroid carcinoma","correct":true,"visible":false}]},{"id":13570,"text":"Which of the following changes is made to the dosage of levothyroxine for a pregnant woman in her 2nd trimester?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 641.","responses":[{"text":"Stop medication","correct":false,"visible":false},{"text":"Switch to triiodothyronine","correct":false,"visible":false},{"text":"Give both levothyroxine and triiodothyronine","correct":false,"visible":false},{"text":"Increase dosage","correct":true,"visible":false},{"text":"Decrease dosage","correct":false,"visible":false}]},{"id":13576,"text":"Which drug causes a decrease in insulin resistance by upregulating peroxisome proliferator-activated receptor gamma (PPAR-γ)?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 317.","responses":[{"text":"Acarbose","correct":false,"visible":false},{"text":"Tolbutamide","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Human insulin","correct":false,"visible":false}]},{"id":13997,"text":"The hypothalamus releases both stimulating and inhibiting hormones to control the secretions of the pituitary gland. Which of the following hormone released by the anterior pituitary is secreted by the pituitary gland in both males and females but is functional only in females under normal circumstances?","explanation":"**Prolactin** is a hormone that plays a key role in the female reproductive system, particularly during pregnancy and lactation. In **females**, prolactin stimulates the development of mammary glands and **milk production**. In males, it has a relatively minor role and is not typically functional in the absence of certain medical conditions or disorders.\r\n\r\n***\r\n\r\nVasopressin, also known as antidiuretic hormone (ADH), is produced by the posterior pituitary gland and is involved in regulating water balance and blood pressure in both males and females.\r\n\r\nGrowth hormone or somatotrophic hormone is produced by the anterior pituitary and plays a role in growth and development in both males and females. It is not gender-specific in its function.\r\n\r\nRelaxin is a hormone primarily produced by the corpus luteum during pregnancy in females. It helps relax the uterine muscles and prepare the body for childbirth. While it is mainly functional in females, it is not produced by the pituitary gland.","reference":"(1) Al-Chalabi M, Bass AN, Alsalman I. Physiology, prolactin. In: StatPearls. StatPearls Publishing; 2022. Accessed December 29, 2022. http://www.ncbi.nlm.nih.gov/books/NBK507829/\r\n(2) Weiss G. Relaxin in the male. Biology of Reproduction. Published February 1989. https://pubmed.ncbi.nlm.nih.gov/2497805/","responses":[{"text":"Prolactin","correct":true,"visible":false},{"text":"Relaxin","correct":false,"visible":false},{"text":"Somatotrophic hormone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Vessopressin","correct":false,"visible":false}]},{"id":13999,"text":"In a tutorial during a small group discussion, the facilitator was asking quiz regarding the gross and microscopic structure of the pituitary gland. Which hypophyseal structure receives signals from the hypothalamus via hypophyseal portal vessels?","explanation":"The anterior pituitary is connected to the hypothalamus by a network of blood vessels called the **hypophyseal portal system**. Through this system, the hypothalamus releases various releasing hormones into the portal vessels, which then travel directly to the adenohypophysis. These releasing hormones stimulate or inhibit the secretion of specific hormones from the **adenohypophysis**, regulating various endocrine functions in the body.\r\n\r\n***\r\n\r\nThe supraoptic nucleus is a part of the hypothalamus and is involved in the synthesis and release of oxytocin and vasopressin (antidiuretic hormone).\r\n\r\nThe pars intermedia is a part of the pituitary gland. It plays a role in the production of melanocyte-stimulating hormone (MSH).\r\n\r\nThe paraventricular nucleus is another nucleus within the hypothalamus and is responsible for producing oxytocin and vasopressin.\r\n\r\nThe neurohypophysis, or posterior pituitary, stores and releases oxytocin and vasopressin, which are produced by the hypothalamus. However, it does not receive signals from the hypothalamus via hypophyseal portal vessels; instead, these hormones are transported along nerve fibers from the hypothalamus to the neurohypophysis for release.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 930.","responses":[{"text":"Supraoptic nucleus","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false},{"text":"Neurohypophysis","correct":false,"visible":false},{"text":"Adenohypophysis","correct":true,"visible":false},{"text":"Paraventricular nucleus","correct":false,"visible":false}]},{"id":14016,"text":"A researcher wants to predict changes in systolic blood pressure with respect to the antihypertensive drug dosage that is prescribed. Which of the following analysis technique can help in predicting the change in SBP correctly?","explanation":"**Regression analysis** is specifically designed for understanding and predicting relationships between a **dependent variable** (in this case, the change in SBP) and one or more **independent variables** (such as drug dosage). It provides a mathematical model that can predict SBP based on the prescribed drug dosage, allowing for more accurate and quantitative predictions.\r\n\r\n***\r\n\r\nThe chi-square test is used to analyze categorical data and determine if there is an association between two categorical variables.\r\n\r\nA paired sample student t-test is used to compare the means of two related groups (e.g., before and after treatment). While it can help assess changes in SBP over time, it may not be the best choice for predicting SBP changes with different dosages.\r\n\r\nIndependent sample student t-test is used to compare the means of two independent groups.\r\n\r\nAnalysis of variance (ANOVA) test is used to compare means of more than two groups to determine if there are statistically significant differences between them.","reference":"Dow Lecture Slides, Endocrinology Module-II, Regression analysis, Topic: What is Regression Analysis?","responses":[{"text":"Chi square test","correct":false,"visible":false},{"text":"Analysis of variance test","correct":false,"visible":false},{"text":"Independent sample student T-test","correct":false,"visible":false},{"text":"Paired sample student T-test","correct":false,"visible":false},{"text":"Regression analysis","correct":true,"visible":false}]},{"id":14017,"text":"Which of the following is the most appropriate test for neonatal screening of hypothyroidism?","explanation":"**Neonatal hypothyroidism** is primarily due to thyroid gland dysfunction, and the initial abnormality often involves decreased production of thyroid hormones. In response to low thyroid hormone levels, the pituitary gland releases increased amounts of thyroid-stimulating hormone (TSH) to stimulate the thyroid gland. Therefore, **elevated TSH** levels are typically the earliest and most sensitive indicator of congenital hypothyroidism in newborns.","reference":"(1) Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 455.\r\n(2) Büyükgebiz A. Newborn screening for congenital hypothyroidism. Journal of Clinical Research in Pediatric Endocrinology. Published March 2013. Accessed December 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3608007/","responses":[{"text":"TSH levels","correct":true,"visible":false},{"text":"Free T3, AMP: T4","correct":false,"visible":false},{"text":"Total T4 and AMP: T3 levels","correct":false,"visible":false},{"text":"Thyroid level","correct":false,"visible":false},{"text":"Thyrotropin levels","correct":false,"visible":false}]},{"id":14018,"text":"Toxicity from which of the following drugs can cause a ringing sensation in the ears?","explanation":"**Aspirin**, or acetylsalicylic acid, is known for its potential ototoxicity, meaning it can damage the structures of the inner ear, leading to **tinnitus**. This side effect usually occurs at higher doses or with prolonged use of aspirin.\r\n\r\n***\r\n\r\nIbuprofen is a nonsteroidal anti-inflammatory drug (NSAID) commonly used for pain relief and inflammation. While it can have side effects such as gastrointestinal irritation, it is not typically associated with tinnitus.\r\n\r\nParacetamol, also known as acetaminophen, is primarily used for pain and fever relief. It is generally well-tolerated and does not commonly cause tinnitus.\r\n\r\nOmeprazole is a proton pump inhibitor (PPI) used to reduce stomach acid production. It is not known to cause tinnitus.\r\n\r\nVitamin D is a nutrient essential for bone health and various bodily functions. It is not associated with tinnitus when taken at recommended doses.","reference":"Stolzberg D, Salvi RJ, Allman BL. Salicylate toxicity model of tinnitus. Frontiers in Systems Neuroscience. Published April 20, 2012. Accessed December 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3341117/","responses":[{"text":"Omeprazole","correct":false,"visible":false},{"text":"Ibuprofen","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false},{"text":"Vitamin-D","correct":false,"visible":false},{"text":"Paracetamol","correct":false,"visible":false}]},{"id":14020,"text":"A 40-year-old male ingested Kuchila seeds (Stridnine nux vomica) for sexual wellness considering it to be a herbal medicine. What side effects will he experience considering he ingested the whole seed with pericarp?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 572.","responses":[{"text":"Respiratory distress","correct":false,"visible":false},{"text":"Tonic clonic seizures","correct":false,"visible":false},{"text":"No symptoms","correct":true,"visible":false},{"text":"Muscle weakness","correct":false,"visible":false},{"text":"Muscle rigidity","correct":false,"visible":false}]},{"id":14021,"text":"Strychnine is known to hyper-stimulate the motor nervous system in the anterior horn cells of the spinal cord. What is the mechanism of action of strychnine?","explanation":"Glycine is an inhibitory neurotransmitter in the central nervous system, and it acts by binding to glycine receptors, which have inhibitory effects on motor neurons in the spinal cord. **Strychnine** interferes with this inhibitory process by **competitively** binding to glycine receptors, **blocking glycine** from binding to these receptors. As a result, the inhibitory signals mediated by glycine are inhibited, leading to hyper-excitability of motor neurons and an exaggerated response to stimuli.\r\n\r\nThis hyper-excitability can manifest as muscle rigidity, spasms, and convulsions, making strychnine a highly toxic compound.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 572.","responses":[{"text":"Competitively antagonizes dopamine","correct":false,"visible":false},{"text":"Blocks glycine uptake at neuromuscular junction","correct":false,"visible":false},{"text":"Competitively antagonizes glycine","correct":true,"visible":false},{"text":"Stimulate glycine uptake","correct":false,"visible":false},{"text":"Stimulate GABA uptake","correct":false,"visible":false}]},{"id":14022,"text":"An overdose of aspirin would result in which of the following pH disturbance in a body at a later stage?","explanation":"**Aspirin overdose** can lead to salicylate toxicity, which primarily affects the metabolic system. Salicylates cause an increase in the production of metabolic acids, primarily lactic acid, and ketoacids. This excessive production of acids leads to metabolic acidosis.\r\n\r\nIn severe cases of aspirin overdose, **metabolic acidosis** can become life-threatening and may require medical intervention such as bicarbonate therapy. Respiratory alkalosis can occur initially due to hyperventilation, but as the metabolic acidosis worsens, it becomes the predominant pH disturbance.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 615.","responses":[{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Compensatory metabolic alkalosis","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false}]},{"id":14023,"text":"What is the main fatal outcome following botulinum toxin ingestion?","explanation":"**Botulinum toxin**, produced by *Clostridium botulinum*, causes botulism, a serious paralytic illness. It works by blocking neurotransmitter release at the neuromuscular junction, leading to paralysis. This paralysis typically progresses in a descending fashion, starting with the cranial nerves. The most dangerous aspect of this paralysis is when it affects the respiratory muscles, leading to **respiratory failure**. This is the most common cause of death in untreated cases of botulism.\r\n\r\n***\r\n\r\nWhile botulinum toxin does cause flaccid paralysis, this in itself is not directly fatal. However, it is the paralysis of respiratory muscles, a part of this flaccid paralysis, that can lead to respiratory failure.\r\n\r\nSimilar to flaccid paralysis, muscle weakness is a symptom of botulism but not directly fatal unless it involves the respiratory muscles.\r\n\r\nSeizures are not a typical feature of botulism. The primary mechanism of botulinum toxin is neuromuscular blockade, not central nervous system excitation or disruption that typically leads to seizures.\r\n\r\nWhile hypotension can occur in severe cases due to autonomic nervous system involvement, it is not the primary fatal outcome of botulinum toxin ingestion.","reference":"(1) Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 630.\r\n(2) Botulism. Accessed January 10, 2023. https://www.who.int/news-room/fact-sheets/detail/botulism","responses":[{"text":"Respiratory failure","correct":true,"visible":false},{"text":"Muscle weakness","correct":false,"visible":false},{"text":"Seizures","correct":false,"visible":false},{"text":"Hypotension","correct":false,"visible":false},{"text":"Flaccid paralysis","correct":false,"visible":false}]},{"id":14024,"text":"A large number of wedding guests experienced nausea, vomiting, and diarrhea following ingestion of meatballs at the ceremony waiting 4-6 hours. What type of food poisoning this could be?","explanation":"*Staphylococcus aureus* is known for producing enterotoxins that can cause food poisoning. This type of food poisoning is characterized by a rapid onset of symptoms, typically within **1 to 6 hours** after consuming contaminated food. The symptoms, which include nausea, vomiting, and diarrhea, are a direct result of the **pre-formed toxins** in the food, rather than an infection per se. Meat and meat products, like meatballs, are common sources of *Staphylococcal* contamination.\r\n\r\n***\r\n\r\nWhile certain strains of E. coli can cause food poisoning, they typically have a longer incubation period before the onset of symptoms.\r\n\r\nThe rapid onset of symptoms in this case is more characteristic of toxin-mediated food poisoning rather than infection by the bacteria itself.\r\n\r\nCaused by the bacterium *Clostridium botulinum*, botulism is a serious form of food poisoning. However, it has a longer incubation period, and its hallmark symptoms include muscle paralysis, starting with the cranial nerves.\r\n\r\n*Shigella* infection, or shigellosis, typically presents with fever, stomach cramps, and bloody diarrhea. The incubation period for *Shigella* is usually 1-2 days, and the rapid onset of symptoms in this case does not align with *Shigella* infection.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 629.","responses":[{"text":"E-coli","correct":false,"visible":false},{"text":"Toxin type","correct":true,"visible":false},{"text":"Shigella","correct":false,"visible":false},{"text":"Botulism","correct":false,"visible":false},{"text":"Bacterial type","correct":false,"visible":false}]},{"id":14035,"text":"A 16-year-old female came to the outpatient department with a painless swelling at her left breast which she noticed 6 months back. Upon examination, the lump is non-tender, and firm, at the 9 o'clock position, and is 3x2 cm. What is the most likely diagnosis?","explanation":"**Fibroadenomas** are benign breast tumors that are commonly found in young women, typically in their late teens and early twenties. They are characterized by painless, firm, and mobile lumps in the breast. Fibroadenomas are usually non-tender, and they can vary in size. They often have a well-defined border and are frequently described as \"rubbery\" or \"smooth\" to the touch.\r\n\r\n***\r\n\r\nPhyllodes tumors are relatively rare and typically present as rapidly growing breast lumps.\r\n\r\nCysts are fluid-filled sacs and are usually tender when palpated.\r\n\r\nCarcinomas are malignant breast tumors, and abscesses are collections of pus, both of which are less likely in a 16-year-old patient without other clinical features.","reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1069.\r\n(2) Ajmal M, Khan M, Van Fossen K. Breast fibroadenoma. In: StatPearls. StatPearls Publishing; 2022. Accessed December 31, 2022. http://www.ncbi.nlm.nih.gov/books/NBK535345/","responses":[{"text":"Carcinoma","correct":false,"visible":false},{"text":"Cyst","correct":false,"visible":false},{"text":"Phyllodes tumor","correct":false,"visible":false},{"text":"Abscess","correct":false,"visible":false},{"text":"Fibroadenoma","correct":true,"visible":false}]},{"id":14036,"text":"A 50-year-old male is planning to undergo a total parathyroidectomy for multiple gland diseases. He shows concerns over the life-long management of postoperative hypocalcemia. How would you reassure the patient?","explanation":"**Total parathyroidectomy** is a surgical procedure that involves the removal of all parathyroid glands, which can result in permanent hypoparathyroidism and hypocalcemia. To address the concerns of postoperative hypocalcemia, **auto-transplantation** of a small amount (typically around 50 mg) of **parathyroid tissue** into a different location, such as the **brachioradialis** in the forearm, can be performed during the surgery.\r\n\r\n***\r\n\r\nProviding anxiolytics, convincing the patient that it is an inevitable complication, counseling about the easy availability of calcium supplements, or suggesting a second opinion on surgery, do not directly address the patient's concerns about postoperative hypocalcemia and its management.","reference":"Barczyński M, Gołkowski F, Nawrot I. Parathyroid transplantation in thyroid surgery. Gland Surgery. Published October 2017. Accessed December 31, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5676165/","responses":[{"text":"Provide him anxiolytics","correct":false,"visible":false},{"text":"Counsel regarding auto-transplantation of 50 mg of parathyroid tissue in brachioradialis","correct":true,"visible":false},{"text":"Counsel to make him believe that this is inevitable complication","correct":false,"visible":false},{"text":"Counsel to get second opinion on surgery","correct":false,"visible":false},{"text":"Counsel regarding easy availability of calcium supplements","correct":false,"visible":false}]},{"id":14047,"text":"A 50-year-old female presents with incidental finding of parathyroid adenoma on neck ultrasound. History and medical examination do not reveal any signs or symptoms however she insists on the removal of the adenoma. What criteria will justify parathyroidectomy in this patient?","explanation":null,"reference":"William NS, O’Connell PR, McCaskie AW, eds. Bailey \u0026 Love’s Short Practice of Surgery. 27th ed. CRC Press, Taylor \u0026 Francis Group; 2018: 829.","responses":[{"text":"Urinary tract infection","correct":false,"visible":false},{"text":"Decrease in serum calcium level of more than 5 mg/dl of upper normal limit","correct":false,"visible":false},{"text":"24-hour urinary calcium more than 200 mg","correct":false,"visible":false},{"text":"Reduced bone density","correct":true,"visible":false},{"text":"Medical therapy not possible","correct":false,"visible":false}]},{"id":14048,"text":"A 35-year-old female patient has a history of headaches with vomiting, vision disturbance, and galactorrhea. On examination, she has a loss of peripheral vision in both eyes. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 1280.","responses":[{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Addison's disease","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false},{"text":"Diabetes insipidus","correct":false,"visible":false},{"text":"Optic neuritis","correct":false,"visible":false}]},{"id":14049,"text":"A 42-year-old lady has had a history of lethargy, lack of energy, amenorrhea, and loss of libido for the last year. On examination, she looks pale, with wrinkled skin, and low blood pressure. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 682.","responses":[{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Growth hormone deficiency","correct":false,"visible":false},{"text":"Addison's disease","correct":false,"visible":false},{"text":"Hypopituitarism","correct":true,"visible":false}]},{"id":14050,"text":"A 50-year-old man presented in the outpatient department with muscle weakness, weight loss, extreme fatigue, peptic ulcereration, hypercalcemia, mood disturbances, and pathological fracture of the femur. Clinicians suspect primary hyperparathyroidism as a cause of his illness, what is the best diagnostic test to confirm hyperparathyroidism in this patient?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 663.","responses":[{"text":"Urinary calcium level","correct":false,"visible":false},{"text":"Parathyroid and serum calcium level","correct":true,"visible":false},{"text":"Parathyroid hormone test","correct":false,"visible":false},{"text":"Thyroid function tests","correct":false,"visible":false},{"text":"Serum phosphate level","correct":false,"visible":false}]},{"id":14057,"text":"What is the best management option for treating primary hyperparathyroidism due to parathyroid adenoma?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 664.","responses":[{"text":"Normal saline 0.9%","correct":false,"visible":false},{"text":"Surgical removal of adenoma","correct":true,"visible":false},{"text":"Denusumab","correct":false,"visible":false},{"text":"Cinacalcet","correct":false,"visible":false},{"text":"Bisphosphonates","correct":false,"visible":false}]},{"id":14058,"text":"A 57-year-old lady presented in the outpatient department with a complaint of frequent semi-solid stools and palpitation. She lost 8kg weight in the past 6 months. On examination, she has had lumpy bumpy painless swelling in her neck for 20 years. What would be the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1092.","responses":[{"text":"Graves disease","correct":false,"visible":false},{"text":"Multinodular goiter with thyrotoxicosis","correct":true,"visible":false},{"text":"Thyroid adenoma","correct":false,"visible":false},{"text":"Sub-acute thyroiditis","correct":false,"visible":false},{"text":"Papillary thyroid carcinoma","correct":false,"visible":false}]},{"id":14059,"text":"A 35-year-old lady presented to the outpatient department with the complaint of an increase in appetite, weight loss and sweating for the past 3 months. She has a gritty sensation in her eyes. On examination, her hands are moist and warm. The thyroid gland is palpable with a bruit. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 631.","responses":[{"text":"Single hyper functioning thyroid nodule","correct":false,"visible":false},{"text":"Graves disease","correct":true,"visible":false},{"text":"Multinodular goiter with thyrotoxicosis","correct":false,"visible":false},{"text":"Sub-acute thyroiditis","correct":false,"visible":false},{"text":"Simple goiter","correct":false,"visible":false}]},{"id":14060,"text":"A 26-year-old male patient with a history of depression complained of abdominal pain for the last 4 months, an account of 4 Kg weight loss, and the patient feels light headiness on walking. There is a history of abdominal tuberculosis for which he completed the treatment. On examination, the patient is anemic and their blood pressure is 90/60 mmHg. Lab results showed serum sodium of 129 mg/dl, potassium of 4.9 mg/dl, and creatinine of 1.0 mg/dl. What is the most likely investigation to confirm this diagnosis?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 303.","responses":[{"text":"Adrenocorticotrophic hormone levels","correct":false,"visible":false},{"text":"Dexamethasone suppression test","correct":false,"visible":false},{"text":"Thyroid stimulating hormone levels","correct":false,"visible":false},{"text":"Cosyntropin stimulation test","correct":true,"visible":false},{"text":"Serum cortisol levels","correct":false,"visible":false}]},{"id":14061,"text":"A 22-year-old female girl came to the outpatient department with complaints of fatigue, reduced stamina, weakness, anorexia, and weight loss in the last three months. On examination, there is an increased pigmentation on palmer creases. What is the most likely abnormality present in this patient?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 672.","responses":[{"text":"Hypernatremia and hypokalemia","correct":false,"visible":false},{"text":"Hypocalcemia","correct":false,"visible":false},{"text":"Hyponatremia and hyperkalemia","correct":true,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false}]},{"id":14062,"text":"A 56-year-old man was taking medications for osteoporosis secondary to hyperparathyroidism and recently was diagnosed with osteosarcoma. Which of the following medications he must be using?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 350.","responses":[{"text":"Teriparatide","correct":true,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Fosamax","correct":false,"visible":false},{"text":"Cinacalcet","correct":false,"visible":false},{"text":"Strontium","correct":false,"visible":false}]},{"id":14137,"text":"A 30-year-old woman was diagnosed with a case of hyperthyroidism due to graves disease. She looks healthy otherwise. In graves disease, the common cause of hyperthyroidism is the production of an antibody that causes which of the following?","explanation":null,"reference":"Davies TF, Andersen S, Latif R, et al. Graves’ disease. Nature Reviews. Disease Primers. Published July 2, 2020. https://pubmed.ncbi.nlm.nih.gov/32616746/#","responses":[{"text":"Lack of iodine intake","correct":false,"visible":false},{"text":"Stimulates pituitary thyrotropin releasing hormone and stimulates TSH release","correct":false,"visible":false},{"text":"Bind to thyroid gland thyroglobuline and increases the release of T3 and T4","correct":false,"visible":false},{"text":"Activates thyroid hormone receptors in peripheral tissues","correct":false,"visible":false},{"text":"Activates thyroid gland TSH receptors","correct":true,"visible":false}]},{"id":14138,"text":"A 55-years old woman with type 2 diabetes was going to start an oral antidiabetic drug that inhibits renal glucose reuptake from the filtrate, thus reducing blood glucose. Which of the following drugs can it be?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 321.","responses":[{"text":"Acarbose","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Canagliflozin","correct":true,"visible":false},{"text":"Rosiglitazone","correct":false,"visible":false},{"text":"Glipizide","correct":false,"visible":false}]},{"id":14139,"text":"A 23-year-old woman with asthma started the therapy with budesonide, an inhaled steroid. The topical administration and short half-life greatly reduce the risk of systemic side effects compared with oral prednisone. The long-term daily administration of the therapeutic doses of prednisone results in which of the following?","explanation":"Long-term use of **oral corticosteroids**, such as prednisone, can lead to a variety of side effects. One of the well-documented side effects is the **reduction in bone density**, which increases the risk of osteoporosis and fractures. This occurs because corticosteroids interfere with the normal process of bone remodeling, leading to decreased bone formation and increased bone resorption.\r\n\r\n***\r\n\r\nHyperplasia of cells in zona fasciculata and reticularis of adrenal cortex is more associated with chronic exposure to excess endogenous glucocorticoids rather than exogenous prednisone.\r\n\r\nWhile corticosteroids can cause various hematological changes, including an increase in white blood cells and a decrease in eosinophils, they are not a common cause of anemia.\r\n\r\nElevated serum calcium levels are not typically associated with long-term prednisone use; instead, they may occur in conditions like hyperparathyroidism or excessive vitamin D intake.\r\n\r\nIncreased male pattern hair growth in women is not a typical side effect of long-term prednisone use; instead, it is more related to conditions like polycystic ovarian syndrome (PCOS) or hirsutism.","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 349.","responses":[{"text":"Hyperplasia of cells in zona fasciculata and reticularis of adrenal cortex","correct":false,"visible":false},{"text":"Elevated serum calcium concentration","correct":false,"visible":false},{"text":"Increased male pattern hair growth in women","correct":false,"visible":false},{"text":"Decreased bone density","correct":true,"visible":false},{"text":"Anemia","correct":false,"visible":false}]},{"id":14140,"text":"A 15-year-old boy with diabetes Melllitus type-1 was brought to the emergency department complaining of dizziness. Laboratory reports show severe hypoglycemia and ketoacidosis. Which of the following substances can be administered to achieve rapid control of severe ketoacidosis?","explanation":"**Severe ketoacidosis** is a life-threatening complication of diabetes mellitus type 1 characterized by high blood glucose levels, ketone production, and metabolic acidosis. The administration of insulin is essential to lower blood glucose levels and suppress further ketone production. **Crystalline zinc insulin**, often in the form of regular insulin, acts relatively quickly and is used intravenously to bring down blood glucose levels rapidly in cases of severe ketoacidosis.\r\n\r\n***\r\n\r\nInsulin glargine, NPH insulin, tolbutamide, and glyburide, are not suitable for rapidly controlling severe ketoacidosis because they have slower onsets of action compared to crystalline zinc insulin or regular insulin.","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 314.","responses":[{"text":"Crystalline zinc insulin","correct":true,"visible":false},{"text":"Insulin glargine","correct":false,"visible":false},{"text":"Glyburide","correct":false,"visible":false},{"text":"NPH insulin","correct":false,"visible":false},{"text":"Tolbutamide","correct":false,"visible":false}]},{"id":14141,"text":"A 47-year-old man exhibited signs and symptoms of acromegaly. Radiological studies indicate the presence of a large pituitary tumor. Surgical treatment of this disease is only partially effective in controlling the disease. At this point, which of the following drugs is most likely to be used as a pharmacological therapy?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 304.","responses":[{"text":"Leuprolide","correct":false,"visible":false},{"text":"Somatotrophin","correct":false,"visible":false},{"text":"Desmopressin","correct":false,"visible":false},{"text":"Cosyntropin","correct":false,"visible":false},{"text":"Octreotide","correct":true,"visible":false}]},{"id":14142,"text":"A 25-year-old female comes to the outpatient department with a complaint of inability to tolerate heat. She says she experiences excessive sweats and drastic weight loss. The physician found signs and symptoms of thyrotoxicosis and diagnosed it as primary hyperthyroidism. Which of the following accurately describes the lab findings in this patient?","explanation":null,"reference":"Nygaard B. Hyperthyroidism(Primary). BMJ Clin Evid. 2008;2008:0611. Accessed January 4, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2907936/","responses":[{"text":"Low TSH, high T3 and T4","correct":true,"visible":false},{"text":"Normal TSH, high T3, T4","correct":false,"visible":false},{"text":"Low TSH, low T3, T4","correct":false,"visible":false},{"text":"High TSH, high T3, T4","correct":false,"visible":false},{"text":"No change in the levels of TSH, T3 and T4","correct":false,"visible":false}]},{"id":14143,"text":"A 25-year-old woman ended up in the emergency department with fever, palpitations, excessive sweating, vomiting, and diarrhea. On investigation, her T3, and T4 was found to be significantly raised. A diagnosis of thyroid storm was made. This condition is associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1084.","responses":[{"text":"Grave's disease","correct":true,"visible":false},{"text":"Reidel's thyroiditis","correct":false,"visible":false},{"text":"De Quervain's thyroiditis","correct":false,"visible":false},{"text":"Subacute lymphocytic thyroiditis","correct":false,"visible":false},{"text":"Hashimoto's thyroiditis","correct":false,"visible":false}]},{"id":14144,"text":"Parents of a 5-year-old boy noticed that he has developed features that suggest puberty over the past 6 months. On examination, the boy has secondary sex characteristics, including pubic hair, and enlargement of the penis. Which of the following morphological features is most likely to be seen in his adrenal glands?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1128.","responses":[{"text":"Normal size and architecture","correct":false,"visible":false},{"text":"Bilateral adrenal cortical atrophy","correct":false,"visible":false},{"text":"Nodule in the adrenal medulla","correct":false,"visible":false},{"text":"Nodule in the adrenal cortex","correct":false,"visible":false},{"text":"Bilateral adrenal cortical hyperplasia","correct":true,"visible":false}]},{"id":14145,"text":"A 45-year-old woman reports a feeling of fullness in her neck without any other complaints. This enlargement has been gradual and painless for more than 1 year. Physical examination confirms diffuse enlargement of the thyroid gland without any apparent masses. Laboratory studies of thyroid function show a normal free T4 level and a slightly increased TSH level. Imaging shows a solitary, spherical, encapsulated lesion that is demarcated from the surrounding thyroid parenchyma by a well-defined, intact capsule. What is the most likely cause of these findings?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1093-1094.","responses":[{"text":"Papillary carcinoma","correct":false,"visible":false},{"text":"Subacute granulomatous thyroiditis","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false},{"text":"Toxic multinodular goiter","correct":false,"visible":false},{"text":"Follicular adenoma","correct":true,"visible":false}]},{"id":14146,"text":"A 55-year-old otherwise healthy man feels a small lump on the left side of his neck. His physician palpates a firm, painless, 2 cm cervical lymph node. The thyroid gland is not palpable. A chest radiograph is unremarkable. Laboratory findings include calcium of 9.1 mg/ dL, phosphorus is 3.3 mg/dL, thyroxine of 8.7 micrograms, and TSH is 2.3 mU/L. Hemoglobin, blood cells, and platelet count are normal. Fine needle aspiration of the thyroid gland was done and the following structures appeared under a microscope, \"The nuclei of cells contain finely dispersed chromatin, which imparts an optically clear or empty appearance, giving rise to the ground-glass or Orphan Annie eye nuclei. In addition, invaginations of the cytoplasm give the appearance of intranuclear inclusions\". What is the most likely diagnosis in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1096.","responses":[{"text":"Anaplastic carcinoma","correct":false,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false},{"text":"Medullary carcinoma","correct":false,"visible":false},{"text":"Follicular carcinoma","correct":false,"visible":false},{"text":"Papillary carcinoma","correct":true,"visible":false}]},{"id":14147,"text":"A 40-years old male presented to the clinic with the complaint of polyuria, and polydipsia. His lab revealed an HBa1C of 6.1%. What is the interpretation of the results?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1099.","responses":[{"text":"Diabetic value","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Impaired value","correct":true,"visible":false},{"text":"Non diabetic value","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false}]},{"id":14148,"text":"a 45-year-old patient comes to the outpatient department with headaches, dizziness, confusion, and irritability. The physician performs an eye examination and finds a loss of vision in the visual fields. What kind of visual field loss is observed in pituitary adenoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1075.","responses":[{"text":"Nasal loss in left eye","correct":false,"visible":false},{"text":"Temporal loss in right eye","correct":false,"visible":false},{"text":"Complete loss in both eyes","correct":false,"visible":false},{"text":"Bitemporal in both eyes","correct":true,"visible":false},{"text":"Binasal in both eyes","correct":false,"visible":false}]},{"id":14149,"text":"Which one of the following would be the most appropriate statistical test to compare the proportions for passing the annual exam among males and females undergraduates students?","explanation":null,"reference":"Dow Lecture slides: Endocrinology module-II, Subject: Biostatistics, Topic: Chi Square test, Sub-topic: Types of Chi square tests.","responses":[{"text":"ANOVA","correct":false,"visible":false},{"text":"Dependent sample test","correct":false,"visible":false},{"text":"Independent sample test","correct":false,"visible":false},{"text":"Chi square test","correct":true,"visible":false},{"text":"Mc Nemar test","correct":false,"visible":false}]},{"id":14150,"text":"The Chi-square test is the most appropriate statistical test to apply to a data set when the researcher wants to compare the difference between which of the following?","explanation":null,"reference":"Yeager K. Libguides: spss tutorials: chi-square test of independence. Accessed January 4, 2023. https://libguides.library.kent.edu/SPSS/ChiSquare","responses":[{"text":"Two or more categorical  variables","correct":true,"visible":false},{"text":"Dependent data for categorical variables","correct":false,"visible":false},{"text":"Two independent continues variables","correct":false,"visible":false},{"text":"Between more than two continuous variables","correct":false,"visible":false},{"text":"Dependent data for continuous variables","correct":false,"visible":false}]},{"id":14151,"text":"A researcher predicted a relationship between salt consumption in milligrams and a change in blood pressure in millimeters of mercury. considering the prediction equation y= a+bx. the change in the blood pressure in this equation is denoted by which of the following letters?","explanation":null,"reference":"Schneider A, Hommel G, Blettner M. Linear regression analysis. Deutsches Ärzteblatt International. Published November 2010. Accessed January 4, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2992018/","responses":[{"text":"b","correct":false,"visible":false},{"text":"y","correct":true,"visible":false},{"text":"x","correct":false,"visible":false},{"text":"a","correct":false,"visible":false},{"text":"both a and b","correct":false,"visible":false}]},{"id":21426,"text":"Which of the following is a first-line treatment of primary hyperparathyroidism?","explanation":"**Primary hyperparathyroidism** is a condition characterized by the overproduction of parathyroid hormone (PTH) by the parathyroid glands, which are located in the neck. The mainstay of treatment for primary hyperparathyroidism is surgical removal (**parathyroidectomy**) of the abnormal parathyroid gland(s) that are causing the excess production of PTH. This can help prevent complications associated with high levels of PTH, such as hypercalcemia (elevated calcium levels), kidney stones, and bone loss.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 664.","responses":[{"text":"Calcium supplements","correct":false,"visible":false},{"text":"Antithyroid drugs","correct":false,"visible":false},{"text":"Calcium blockers","correct":false,"visible":false},{"text":"Parathyroidectomy","correct":true,"visible":false},{"text":"Iodine","correct":false,"visible":false}]},{"id":21566,"text":"A 12-year-old child presents with lethargy, constipation, and pain in calf for 3 months. On examination, he has protruded abdomen and coarse facial skin. Which is the single best investigation to confirm the diagnosis?","explanation":"The clinical presentation of a child with lethargy, constipation, pain in the calf, a protruded abdomen, coarse facial skin, and possible thyroid dysfunction suggests the possibility of **hypothyroidism.** Hypothyroidism can occur in children and can lead to a range of symptoms, including growth and developmental issues.\r\n\r\nThe measurement of **serum T4** (thyroxine) and thyroid-stimulating hormone (TSH) levels is a fundamental and sensitive investigation for diagnosing thyroid disorders. In hypothyroidism, serum T4 levels are typically decreased, while TSH levels are elevated as the body tries to compensate for the reduced thyroid hormone levels by increasing TSH production.","reference":"Khan, Parvez Akbar. Basis of Pediatrics. 10th ed., Paramount Books (Pvt.) Ltd, 2018: 451.","responses":[{"text":"Serum T4 and TSH","correct":true,"visible":false},{"text":"Serum T3","correct":false,"visible":false},{"text":"Serum ACTH","correct":false,"visible":false},{"text":"Levels of TRH","correct":false,"visible":false},{"text":"Serum Iodine levels","correct":false,"visible":false}]},{"id":21575,"text":"A farmer while spraying his fields fell suddenly ill and was brought to the emergency department, with complaints of nausea, dyspnea, abdominal cramps, chest pain, and blurred vision. Which of the following is the most accurate diagnosis in this case?","explanation":"Organophosphate compounds are commonly used as pesticides in agriculture, and exposure to them can result in poisoning. **Organophosphate poisoning** typically includes cholinergic symptoms due to excessive stimulation of the parasympathetic nervous system. These symptoms can include nausea, abdominal cramps, chest tightness or pain, blurred vision (due to miosis or constricted pupils), excessive salivation, and muscle weakness. In severe cases, it can lead to respiratory distress, seizures, and even death.\r\n\r\nThe **antidote** for organophosphate poisoning is **atropine**, which can reverse the cholinergic symptoms. Therefore, atropine administration is a crucial part of the treatment for organophosphate poisoning.","reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 597.","responses":[{"text":"Angina attack","correct":false,"visible":false},{"text":"Pollen allergy","correct":false,"visible":false},{"text":"Atropine poisoning","correct":false,"visible":false},{"text":"Organophospate poisoning","correct":true,"visible":false},{"text":"Stroke","correct":false,"visible":false}]},{"id":21577,"text":"A 30-year-old female comes to the clinic with the complaint of painless swelling on the left side of the neck for 3 months. Detailed history and examination reveal she has palpitations, heat intolerance, sweating, and frequent diarrhea. Her pulse is 110 beats/min, blood pressure is 110/80 mmHg. Her palms are moist but no tremors are observed. There is about 4 x 4 cm, soft, non-tender, swelling present in the right lobe and isthmus, which is moving upon deglutition. Radioiodine shows homogenous uptake. She has decreased thyroid-stimulating hormone (TSH) levels with increased free T3 and T4 levels. What is the best treatment option for this case?","explanation":"Painless swelling on the left side of the neck, palpitations, heat intolerance, sweating, and frequent diarrhea, along with a soft, non-tender swelling in the thyroid gland, is suggestive of Graves' disease. **Graves' disease** is an autoimmune disorder characterized by an overactive thyroid gland (hyperthyroidism) and diffuse goiter.\r\n\r\nThe following factors support the choice of **total lobectomy and isthmectomy**:\r\n\r\nRadioiodine uptake: The presence of homogeneous uptake on a radioiodine scan indicates diffuse involvement of the thyroid gland, which is typical in Graves' disease.\r\n\r\nHyperthyroidism: The patient has clinical signs of hyperthyroidism, including palpitations, heat intolerance, sweating, and diarrhea. The laboratory findings of decreased TSH levels with increased free T3 and T4 levels confirm the diagnosis of hyperthyroidism.\r\n\r\nThyroid size: A 4 x 4 cm goiter suggests significant enlargement of the thyroid gland, which may require surgical intervention.","reference":"(1) Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 643.\r\n\r\n(2) O’Connell, P. Ronan, et al., editors. Bailey \u0026 Love’s Short Practice of Surgery. 28th ed., CRC Press, Taylor \u0026 Francis Group, 2023: 860.","responses":[{"text":"Near total thyroidectomy","correct":false,"visible":false},{"text":"Total lobectomy and isthmectomy","correct":true,"visible":false},{"text":"Subtotal thyroidectomy","correct":false,"visible":false},{"text":"Left lobe lobectomy","correct":false,"visible":false},{"text":"Thyroidectomy","correct":false,"visible":false}]},{"id":21579,"text":"A 29-year-old patient comes with complaints of fever and sore throat. On examination, her throat is congested and her thyroid is palpable. She has no signs and symptoms of thyroid disease and neither has a positive family history.  Labs reveal low TSH and T3 levels while her T4 is raised. What is the possible diagnosis?","explanation":"**Sick euthyroidism**, also known as euthyroid sick syndrome or non-thyroidal illness syndrome (NTIS), is a condition in which thyroid function tests (TFTs) appear abnormal in the setting of acute or severe illness, but there is no underlying thyroid disease.\r\n\r\nThe patient's presentation with fever, sore throat, and a palpable thyroid gland suggests an acute illness or infection. In sick euthyroidism, the thyroid function tests may show a variety of abnormalities, such as low TSH, low T3 levels, and normal or elevated T4 levels. These changes in TFTs are typically a result of the body's response to the stress of illness rather than a primary thyroid disorder.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 642.","responses":[{"text":"Sick euthyroidism","correct":true,"visible":false},{"text":"Subclinical hypothyroidism","correct":false,"visible":false},{"text":"Nodular thyroid disease","correct":false,"visible":false},{"text":"Thyrotoxicosis","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false}]},{"id":21583,"text":"Which of the following is the most likely diagnosis if a technetium pertechnetate scan of a patient shows diffuse uptake of an isotope?","explanation":"**Graves' disease** is an autoimmune disorder that leads to the overproduction of thyroid hormones by the thyroid gland. One of the characteristic features of Graves' disease is **diffuse and symmetric uptake** of radiolabeled iodine or pertechnetate on a thyroid scan. This diffuse uptake pattern is often referred to as a \"hot\" thyroid, indicating increased thyroid activity and hormone production.\r\n\r\n***\r\n\r\nIodine-induced thyroiditis may lead to a \"cold\" or non-uptake pattern on a thyroid scan due to thyroid gland damage.\r\n\r\nHypothyroidism, whether due to autoimmune thyroiditis or other causes, is associated with reduced thyroid activity and may result in a \"cold\" thyroid scan.\r\n\r\nWhile multinodular goiter can have areas of increased uptake within the nodules, it usually does not result in the diffuse and symmetric uptake pattern seen in Graves' disease.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 638.","responses":[{"text":"Graves disease","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Iodine-induced thyroiditis","correct":false,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Iodine-induced thyroiditis","correct":false,"visible":false}]},{"id":21592,"text":"Which of the following is described as a powerful statistical method that allows you to examine the relationship between two or more variables of interest in which the influence of one or more independent variables on a dependent variable can be studied?","explanation":"**Regression analysis** is widely used in statistics to understand and model the relationships between variables. It can help determine how changes in one or more independent variables are associated with changes in a dependent variable. There are various types of regression analysis, including simple linear regression, multiple linear regression, and logistic regression, each suited to different types of data and research questions.\r\n\r\n***\r\n\r\nT-test is used to compare the means of two groups to determine if there is a significant difference between them.\r\n\r\nChi-square is used for categorical data to determine if there is an association or independence between two categorical variables.\r\n\r\nMANOVA is used when you have two or more dependent variables and one or more categorical independent variables to determine if there are significant differences among groups in terms of the dependent variables.\r\n\r\nANOVA is used to compare means among three or more groups to determine if there are statistically significant differences.","reference":"“Regression Analysis.” Corporate Finance Institute, https://corporatefinanceinstitute.com/resources/data-science/regression-analysis/. Accessed 15 Dec. 2023.","responses":[{"text":"Chi-square","correct":false,"visible":false},{"text":"MANOVA","correct":false,"visible":false},{"text":"T-test","correct":false,"visible":false},{"text":"Regression analysis","correct":true,"visible":false},{"text":"ANOVA","correct":false,"visible":false}]},{"id":21601,"text":"Which of the following is a corticosteroid of choice in Addison's disease?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 673.","responses":[{"text":"Budesonide","correct":false,"visible":false},{"text":"Fludrocortisone","correct":false,"visible":false},{"text":"Hydrocortisone","correct":true,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Beclomethasone","correct":false,"visible":false}]},{"id":21602,"text":"A patient presented to the outpatient department with complaints of dysphagia, fatigue, weight loss, hypotension, abdominal pain, and hyperpigmentation at the areas exposed to sun and friction. Which of the following can be given in this case?","explanation":"Dysphagia, fatigue, weight loss, hypotension, abdominal pain, and hyperpigmentation, especially in sun-exposed and friction-prone areas, are indicative of a condition known as Addison's disease or adrenal insufficiency. Addison's disease is characterized by the insufficient production of adrenal hormones, including cortisol and aldosterone.\r\n\r\n**Intravenous hydrocortisone** is the appropriate treatment for acute adrenal crisis, which can occur in patients with Addison's disease. This crisis can be life-threatening and requires immediate administration of glucocorticoids (like hydrocortisone) to replace the deficient cortisol, stabilize blood pressure, and correct electrolyte imbalances.\r\n\r\n***\r\n\r\nIncreased dose of ATT (anti-tuberculosis treatment), intravenous Ringer's lactate, intravenous saline 0.9%, and intravenous dextrose 5%, do not address the primary issue of adrenal insufficiency in this patient.","reference":"Addison’s Disease - Treatment.” Nhs.Uk, 20 Oct. 2017, https://www.nhs.uk/conditions/addisons-disease/treatment/.","responses":[{"text":"Intravenous dextrose 5%","correct":false,"visible":false},{"text":"Intravenous saline 0.9%","correct":false,"visible":false},{"text":"Increased dose of ATT","correct":false,"visible":false},{"text":"Intravenous ringer's lactate","correct":false,"visible":false},{"text":"Intravenous hydrocortisone","correct":true,"visible":false}]},{"id":21603,"text":"Glucocorticoid is given in adrenal hyperplasia to achieve which of the following?","explanation":"In **adrenal hyperplasia**, which can be caused by conditions like congenital adrenal hyperplasia (CAH) or other disorders, there is an overproduction of adrenal hormones, including cortisol. This overproduction often results from a deficiency in an enzyme involved in the synthesis of cortisol.\r\n\r\nACTH is the hormone responsible for stimulating the adrenal glands to produce cortisol. By **suppressing ACTH production**, **glucocorticoid** therapy helps control the excessive secretion of cortisol, preventing its harmful effects and maintaining hormonal balance in the body.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 658.","responses":[{"text":"Increase TSH","correct":false,"visible":false},{"text":"Decrease TSH","correct":false,"visible":false},{"text":"Increase ACTH","correct":false,"visible":false},{"text":"Prevent hypoglycemia","correct":false,"visible":false},{"text":"Suppress ACTH","correct":true,"visible":false}]},{"id":21604,"text":"Physical examination of an infant shows a markedly virilized and hypertrophic clitoris with partial fusion of the labioscrotal folds in a female having 46, XX karyotype. Laboratory studies will most likely reveal a deficiency of which of the following?","explanation":"**Congenital adrenal hyperplasia** (CAH), which is most commonly caused by a deficiency in the enzyme **21-hydroxylase.** CAH can result in the overproduction of androgens (male hormones) in females, leading to virilization of the external genitalia in female infants.\r\n\r\nSpecifically, 21-hydroxylase is essential for the synthesis of both mineralocorticoids (such as aldosterone) and glucocorticoids (such as cortisol) in the adrenal glands. When 21-hydroxylase is deficient, there is a shift in the steroid biosynthesis pathway towards the production of excess androgens. This, in turn, can lead to the virilization of the external genitalia in female infants with a 46, XX karyotype.\r\n\r\n***\r\n\r\nCorticotropin, progesterone, prolactin, and androstenedione are not typically deficient in CAH and do not directly contribute to the virilization seen in this condition.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1121.","responses":[{"text":"Corticotropin","correct":false,"visible":false},{"text":"21-hydroxylase","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Androstenedione","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false}]},{"id":21620,"text":"Acromegaly is a condition in which there is an excessive secretion of growth hormone in the body in adults. A patient with this condition can present with which of the following associated metabolic abnormalities?","explanation":"Acromegaly leads to an increased secretion of growth hormone (GH) and, consequently, elevated levels of insulin-like growth factor 1 (IGF-1). These hormonal changes can result in insulin resistance, where the body's cells do not respond effectively to insulin. This can lead to impaired glucose uptake by tissues, potentially causing elevated blood sugar levels (hyperglycemia).","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 986.","responses":[{"text":"Decreased lipolysis","correct":false,"visible":false},{"text":"Insulin resistance","correct":true,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Decreased protein synthesis","correct":false,"visible":false},{"text":"Decreased gluconeogenesis","correct":false,"visible":false}]},{"id":21632,"text":"A 16-year-old girl presented to the outpatient department with a complaint of severe acne, oily skin, excessive body hair, and primary amenorrhea.  She also has an enlarged clitoris. Which of the following tests is not useful in making the diagnosis?","explanation":"Acne, oily skin, excessive body hair, primary amenorrhea, and an enlarged clitoris are suggestive of polycystic ovary syndrome (PCOS). PCOS is characterized by hormonal imbalances that lead to elevated levels of androgens (male hormones) in females.\r\n\r\nCortisol, on the other hand, is not typically a primary marker for diagnosing PCOS or hyperandrogenic disorders like congenital adrenal hyperplasia. Cortisol is more related to adrenal function and disorders such as Cushing's syndrome. While some hormonal imbalances can be associated with PCOS, cortisol testing is not a standard diagnostic tool for this condition.\r\n\r\n***\r\n\r\nElevated levels of testosterone are often seen in PCOS and other hyperandrogenic disorders.\r\n\r\nThe 17-OH-progesterone test is useful for assessing congenital adrenal hyperplasia (CAH), a condition that can present with similar symptoms. Elevated 17-OH-progesterone may indicate CAH.\r\n\r\nElevated levels of androstenedione can also be observed in hyperandrogenic disorders.\r\n\r\nElevated DHEA-S levels may indicate adrenal hyperandrogenism and can be associated with PCOS.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 673.","responses":[{"text":"DHEA-S","correct":false,"visible":false},{"text":"Androstenedione","correct":false,"visible":false},{"text":"Serum testosterone","correct":false,"visible":false},{"text":"17-OH-progesterone","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false}]},{"id":21647,"text":"Which of the following statements is correct regarding the endocrine glands in the body?","explanation":"**Endocrine glands** are known for their **rich blood supply** because they need a well-developed network of blood vessels to transport hormones throughout the body. Unlike exocrine glands, which have ducts to release their secretions into body cavities or onto body surfaces (such as sweat glands or salivary glands), endocrine glands release hormones directly into the bloodstream. These hormones then travel to target organs or tissues to regulate various physiological processes.\r\n\r\n***\r\n\r\nEndocrine glands are not necessarily low in vascularity; they require a significant blood supply to transport hormones.\r\n\r\nEndocrine glands are not completely independent of the nervous system; they often interact with the nervous system to regulate hormone secretion.\r\n\r\nEndocrine glands do not typically have ducts. Instead, they release hormones directly into the bloodstream.\r\n\r\nEndocrine glands do not have large ducts; their secretions enter the bloodstream through tiny capillaries.","reference":"Laiq Hussain Siddiqui. Medical Histology Text And Atlas. 6th ed., Paramount, 2019: 151.","responses":[{"text":"They have small ducts","correct":false,"visible":false},{"text":"They have abundant blood supply","correct":true,"visible":false},{"text":"They are completely independent of nervous system","correct":false,"visible":false},{"text":"They have large ducts","correct":false,"visible":false},{"text":"They have low vascularity","correct":false,"visible":false}]},{"id":21648,"text":"Which of the following is used in the treatment of Addison's disease?","explanation":"**Addison's disease**, also known as primary adrenal insufficiency, results from a deficiency of adrenal hormones, particularly cortisol and aldosterone. Hydrocortisone is used in Addison's disease treatment to replace cortisol, which is deficient in these patients.\r\n\r\n***\r\n\r\nBeclomethasone and budesonide are corticosteroids used for different purposes, such as treating asthma and inflammatory bowel disease, but they are not typically used to manage Addison's disease.\r\n\r\nAldosterone, while deficient in Addison's disease, is not directly used as a medication to treat the condition.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 673","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Fludrocortisone","correct":false,"visible":false},{"text":"Beclomethasone","correct":false,"visible":false},{"text":"Hydrocortisone","correct":true,"visible":false},{"text":"Budesonide","correct":false,"visible":false}]},{"id":21649,"text":"Which of the following oral hypoglycemic drugs can cause an increased risk of hypoglycemia in a patient with renal impairment?","explanation":"**Glyburide** (also known as glibenclamide) is a sulfonylurea medication commonly used to lower blood sugar levels in individuals with type 2 diabetes. One of the potential side effects of sulfonylureas like glyburide is **hypoglycemia**.\r\n\r\nIn patients with renal impairment, especially those with severe impairment, the clearance of glyburide from the body is reduced. This can lead to the accumulation of the drug, resulting in a prolonged and increased hypoglycemic effect. Therefore, individuals with renal impairment are at a higher risk of experiencing hypoglycemia when taking glyburide.\r\n\r\n***\r\n\r\nMetformin is generally safe in renal impairment and does not cause hypoglycemia as a primary side effect.\r\n\r\nHydrocortisone is not an oral hypoglycemic drug; it is a steroid hormone used to treat conditions like adrenal insufficiency.\r\n\r\nAcarbose is an alpha-glucosidase inhibitor that does not commonly cause hypoglycemia.\r\n\r\nPioglitazone is a thiazolidinedione that primarily improves insulin sensitivity and does not significantly increase the risk of hypoglycemia.","reference":"Karen Whalen, et al. Lippincott Illustrated Reviews: Pharmacology. 7th ed., Lippincott Williams \u0026 Wilkins, 2019: 318.","responses":[{"text":"Metformin","correct":false,"visible":false},{"text":"Acarbose","correct":false,"visible":false},{"text":"Hydrocortisone","correct":false,"visible":false},{"text":"Glyburide","correct":true,"visible":false},{"text":"Pioglitazone","correct":false,"visible":false}]},{"id":21693,"text":"An 8-year-old child presents to the outpatient department for short height. His height is 106 cm, and his weight is 16 kg. He was normal at birth. He looks chubby and immature but with a normal IQ. Growth velocity is decreased. X-ray shows delayed bone age at 3 years. The most likely cause of short stature in this child would be which of the following?","explanation":"The **delayed bone age, significantly behind chronological age**, and **reduced growth velocity** supports a diagnosis of a hormonal issue affecting growth rather than simply familial short stature or constitutional delay, which typically would not show such a marked delay in bone maturation.\r\n\r\nHypothyroidism can also cause delayed growth and bone age, along with symptoms of fatigue, cold intolerance, and constipation. While it remains a possible cause, the child's described chubby and immature appearance with significantly delayed bone age is more characteristic of growth hormone deficiency.\r\n\r\nFamilial short stature usually presents with a family history of short stature, and the growth velocity and bone age are typically normal or proportional to the family pattern.\r\n\r\nConstitutional delay of growth and puberty often presents with delayed growth and puberty in children who eventually catch up later in adolescence. These children have a normal growth velocity for their bone age, which is delayed but not usually as severely as described here.\r\n\r\nMalnutrition could cause growth delays, but the child's presentation (normal IQ, chubby appearance) does not align with the typical manifestations of chronic malnutrition, which often includes underweight or wasting rather than being chubby.","reference":"Barstow C, Rerucha C. Evaluation of short and tall stature in children. AFP. 2015;92(1):43-50. Accessed February 10, 2024. https://www.aafp.org/pubs/afp/issues/2015/0701/p43.html","responses":[{"text":"Malnutrition","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Growth hormone deficiency","correct":true,"visible":false},{"text":"Constitutional delay","correct":false,"visible":false},{"text":"Familial short stature","correct":false,"visible":false}]},{"id":21694,"text":"A 15-year-old boy presents to the outpatient department with backache, moon face, muscle weakness, and truncal obesity. On examination, the child has elevated blood pressure and delayed reflexes. The laboratory results show increased cortisol levels. Which of the following hormones would be increased in the patient?","explanation":"Backache, moon face, muscle weakness, truncal obesity, elevated blood pressure, and increased cortisol levels, strongly suggest **Cushing syndrome**. Cushing syndrome is characterized by an **excess of cortisol** production.\r\n\r\n***\r\n\r\nThyroid-releasing hormone (TRH) primarily stimulates the release of thyroid-stimulating hormone (TSH) from the anterior pituitary gland, leading to thyroid hormone production.\r\n\r\nEpinephrine is produced by the adrenal medulla and is not typically increased in Cushing's syndrome.\r\n\r\nGrowth hormone (GH) is produced by the anterior pituitary gland and is not directly related to the symptoms of Cushing's syndrome.\r\n\r\nAldosterone is a mineralocorticoid hormone produced by the adrenal glands, but its excess is associated with conditions like primary hyperaldosteronism, not Cushing's syndrome.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 170.","responses":[{"text":"Cortisol","correct":true,"visible":false},{"text":"Thyroid releasing hormone","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false}]},{"id":21695,"text":"A 57-year-old woman presents with amenorrhea and emotional disturbances. She has upper truncal obesity. Laboratory results show elevated serum levels of cortisol, which can be lowered by the administration of dexamethasone. Which of the following is the most likely cause of hypercortisolism in this patient?","explanation":"Amenorrhea, emotional disturbances, upper truncal obesity, and elevated cortisol levels that can be lowered by dexamethasone administration suggest **ACTH-dependent Cushing syndrome**, where the excess cortisol is stimulated by an overproduction of adrenocorticotropic hormone (ACTH).\r\n\r\nTherefore, the most likely cause of hypercortisolism in this patient is a **pituitary adenoma**, specifically a corticotroph adenoma, which leads to increased production of ACTH, subsequently stimulating the adrenal glands to produce excess cortisol.\r\n\r\n***\r\n\r\nAdrenal cortical adenoma, pheochromocytoma, adrenal cortical hyperplasia, and adrenal cortical carcinoma, are less likely to cause ACTH-dependent hypercortisolism with elevated serum cortisol levels that respond to dexamethasone suppression.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1115.","responses":[{"text":"Adrenal cortical hyperplasia","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":true,"visible":false},{"text":"Adrenal cortical carcinoma","correct":false,"visible":false},{"text":"Adrenal cortical adenoma","correct":false,"visible":false}]},{"id":21811,"text":"Which of the following is the most common adverse effect of tolbutamide when given in excess?","explanation":"**Tolbutamide** is an oral antidiabetic medication that belongs to the class of drugs known as sulfonylureas. It works by stimulating the release of insulin from the pancreas, which helps lower blood sugar levels. However, when taken in excess or without proper monitoring, sulfonylureas like tolbutamide can lead to **prolonged hypoglycemia**.\r\n\r\n***\r\n\r\nTolerance to alcohol is not a common adverse effect of tolbutamide.\r\n\r\nDiarrhea and glycosuria (excretion of glucose in the urine) are generally not prominent side effects of sulfonylureas.\r\n\r\nAcidosis is more often associated with other types of diabetes medications or uncontrolled diabetes itself, rather than tolbutamide.","reference":"Costello, Ryan A., et al. “Sulfonylureas.” StatPearls, StatPearls Publishing, 2023. PubMed, http://www.ncbi.nlm.nih.gov/books/NBK513225/.","responses":[{"text":"Diarrhea","correct":false,"visible":false},{"text":"Glycosuria","correct":false,"visible":false},{"text":"Prolonged hypoglycemia","correct":true,"visible":false},{"text":"Acidosis","correct":false,"visible":false},{"text":"Tolerance to alcohol","correct":false,"visible":false}]},{"id":21812,"text":"Which of the following is true regarding the effect of radioiodine on the thyroid parenchyma?","explanation":"**Beta radiation** consists of high-energy electrons or positrons that can penetrate tissues and have a short range. When radioiodine is taken up by the thyroid gland (which predominantly occurs in the follicular cells), the beta radiation emitted by I-131 damages and **destroys** these **follicular cells**.\r\n\r\n***\r\n\r\nParafollicular cells, also known as C cells, are responsible for producing calcitonin, which regulates calcium levels in the body. They are less affected by beta radiation from radioiodine, as the radiation primarily targets the cells involved in thyroid hormone production (follicular cells).\r\n\r\nGamma radiation is high-energy electromagnetic radiation that can also be emitted by radioiodine, but its primary role is in imaging (scintigraphy) to visualize the thyroid gland's function and structure. Alpha particles, on the other hand, are not typically associated with radioiodine.","reference":"Mumtaz, Malik, et al. “Radioiodine I-131 For The Therapy Of Graves’ Disease.” The Malaysian Journal of Medical Sciences : MJMS, vol. 16, no. 1, 2009, pp. 25–33. PubMed Central, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3336179/.","responses":[{"text":"Radioiodine has no effect on the thyroid parenchyma","correct":false,"visible":false},{"text":"Gamma radiation destroys the parafollicular cells","correct":false,"visible":false},{"text":"Beta radiations mainly destroy the follicular cell","correct":true,"visible":false},{"text":"Alpha particles destroy the follicular cells","correct":false,"visible":false},{"text":"Both alpha particles and gamma rays destroy the parafollicular cells","correct":false,"visible":false}]},{"id":21813,"text":"A 12-year-old child is diagnosed with candidiasis. His past medical history is significant for Addison's disease, hypoparathyroidism, and hypocalcemia. Which of the following conditions does the patient have?","explanation":"**Polyglandular syndrome type 1** (PGS-1), also known as autoimmune polyendocrinopathy-candidiasis-ectodermal dystrophy (APECED), is an autosomal recessive disorder. It is classically characterized by the triad of chronic mucocutaneous candidiasis, hypoparathyroidism, and Addison disease.\r\n\r\n***\r\n\r\nPolyglandular syndrome type 2 (PGS-2) is also known as Schmidt syndrome. PGS-2 typically presents in adulthood and involves Addison disease along with either type 1 diabetes or thyroid autoimmune disease. Hypoparathyroidism and candidiasis are not characteristic features of PGS-2.\r\n\r\nAllgrove syndrome, also known as Triple-A syndrome, Allgrove syndrome is characterized by alacrima, achalasia of the esophagus, and adrenal insufficiency. The key features in this case (candidiasis, hypoparathyroidism) are not typical of Allgrove syndrome.\r\n\r\nMultiple endocrine neoplasia type 1 (MEN1) is a condition associated with tumors of the parathyroid glands, pancreatic islet cells, and pituitary gland. While it can include hyperparathyroidism, the combination of hypoparathyroidism, Addison disease, and candidiasis does not fit the typical MEN1 profile.\r\n\r\nMultiple endocrine neoplasia type 2 (MEN2) is associated with medullary thyroid carcinoma, pheochromocytoma, and hyperparathyroidism. The patient's symptoms do not align with the typical manifestations of MEN2.","reference":"Bello, Manuel O., and Vishnu V. Garla. “Polyglandular Autoimmune Syndrome Type I.” StatPearls, StatPearls Publishing, 2023. PubMed, http://www.ncbi.nlm.nih.gov/books/NBK537211/.","responses":[{"text":"Polyglandular syndrome type 1 (PGS-1)","correct":true,"visible":false},{"text":"Multiple endocrine neoplasia type 2 (MEN2)","correct":false,"visible":false},{"text":"Multiple endocrine neoplasia type 1 (MEN1)","correct":false,"visible":false},{"text":"Allgrove syndrome","correct":false,"visible":false},{"text":"Polyglandular syndrome type 2 (PGS-2)","correct":false,"visible":false}]},{"id":21814,"text":"Which of the following is the best management in case of snake bites in remote areas?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 529.","responses":[{"text":"Immobilize the arm and keep it below heart level","correct":true,"visible":false},{"text":"Give antivenom treatment","correct":false,"visible":false},{"text":"Observe the patient for 1 day","correct":false,"visible":false},{"text":"Suck the venom out using mouth or breast pump","correct":false,"visible":false},{"text":"Tie with tourniquet to stop blood","correct":false,"visible":false}]},{"id":21815,"text":"Which of the following accurately describes the manifestation of autoimmune hypothyroidism on lab investigations?","explanation":"Autoimmune hypothyroidism is characterized by the presence of antibodies that attack the thyroid gland, leading to its dysfunction. \r\n\r\nThyroid-stimulating hormone (TSH) levels are typically high because the pituitary gland senses the low levels of thyroid hormones in the blood and tries to stimulate the thyroid to produce more.\r\n\r\nThyroxine (T4) levels are low because the autoimmune attack on the thyroid gland impairs its ability to produce an adequate amount of thyroid hormones.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 636.","responses":[{"text":"High TSH and low T4","correct":true,"visible":false},{"text":"Normal TSH and T4","correct":false,"visible":false},{"text":"High TSH and high T4","correct":false,"visible":false},{"text":"Low TSH and low T4","correct":false,"visible":false},{"text":"Low TSH and high T4","correct":false,"visible":false}]},{"id":21832,"text":"Which of the following is the most likely complication in a patient with diabetes mellitus for 11 years?","explanation":"Patients with diabetes mellitus, especially those with poorly controlled or long-standing diabetes, are at a significantly higher risk of developing cardiovascular complications due to **accelerated atherosclerosis**. This involves the narrowing and hardening of blood vessels, which can lead to various cardiovascular problems, including heart attacks and strokes. Additionally, diabetes can lead to microvascular complications, such as **foot gangrene**, due to poor circulation and nerve damage.\r\n\r\n***\r\n\r\nWhile diabetes can also affect the eyes (diabetic retinopathy), it typically takes a longer time to develop, and the patient's duration of diabetes at 11 years is not the primary risk factor for retinal vein occlusion, tunnel vision, or diminishing vision.\r\n\r\nAccelerated arthritis is not a well-established complication of diabetes.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1107.","responses":[{"text":"Diminishing vision","correct":false,"visible":false},{"text":"Tunnel vision","correct":false,"visible":false},{"text":"Accelerated arthritis","correct":false,"visible":false},{"text":"Retinal vein occlusion","correct":false,"visible":false},{"text":"Accelerated atherosclerosis and foot gangrene","correct":true,"visible":false}]},{"id":21833,"text":"A 45-year-old female presents with a nodule in her thyroid region. Orphan Annie's eye nuclei and invaginations of the nuclear membrane are visible on the microscope. Fine needle aspiration of the nodule material shows psammoma bodies within the cores of papillae. What is the most likely diagnosis?","explanation":"**Papillary thyroid carcinoma** often presents as a **thyroid nodule**, making it a common thyroid cancer. Orphan Annie's eye nuclei refer to the enlarged, irregularly shaped nuclei with a cleared center that are typical of papillary thyroid carcinoma. Invaginations of the nuclear membrane are also seen in the cells. Psammoma bodies are concentric, laminated calcifications commonly found in papillary thyroid carcinoma, among other conditions.\r\n\r\n***\r\n\r\nHürthle cell tumors are usually composed of Hürthle cells and have distinctive features on histology, which are different from those described in this case.\r\n\r\nAnaplastic carcinoma is an aggressive and undifferentiated thyroid cancer. It typically does not present with the characteristic nuclear features seen in papillary carcinoma.\r\n\r\nMedullary thyroid carcinoma arises from parafollicular C cells and has a different histological appearance and clinical presentation compared to papillary carcinoma.\r\n\r\nFollicular carcinoma is another type of thyroid cancer with different histological characteristics, including follicular patterns and invasion of blood vessels.","reference":"Kumar, Vinay, et al. Robbins and Cotran Pathologic Basis of Disease. 9th ed., Elsevier Saunders, 2015: 1088.","responses":[{"text":"Follicular carcinoma","correct":false,"visible":false},{"text":"Medullary cell carcinoma","correct":false,"visible":false},{"text":"Hürthle cell tumor","correct":false,"visible":false},{"text":"Papillary carcinoma","correct":true,"visible":false},{"text":"Anaplastic carcinoma","correct":false,"visible":false}]},{"id":21834,"text":"Which of the following is the most common endogenous cause of the Cushing syndrome?","explanation":"The most common endogenous cause of Cushing syndrome is **Cushing disease**. It is caused by a pituitary adenoma - a non-cancerous tumor of the pituitary gland - that produces excessive adrenocorticotropic hormone (ACTH). This excess ACTH, in turn, stimulates the adrenal glands to produce and release excessive cortisol, leading to Cushing syndrome.\r\n\r\n***\r\n\r\nAdrenal adenomas can cause Cushing syndrome, but they are not the most common endogenous cause.\r\n\r\nAdrenal carcinomas are rare and can lead to Cushing syndrome, but they are less common than Cushing's disease.\r\n\r\nSmall cell lung carcinoma can produce ACTH and cause Cushing syndrome, but it is not the most common endogenous cause.","reference":"Kumar, Vinay, et al. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed., Elsevier, 2020: 785, 786.","responses":[{"text":"Cushing disease","correct":true,"visible":false},{"text":"Adrenal carcinoma","correct":false,"visible":false},{"text":"Adrenal adenoma","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Small cell carcinoma of lung","correct":false,"visible":false}]},{"id":21872,"text":"A 56-year-old female patient who has a history of diabetes and hypertension starts taking amiodarone after her coronary artery bypass surgery. Later, she presents with symptoms of tiredness, sensitivity to cold, weight gain, and constipation. Which of the following is the most likely diagnosis?","explanation":"**Amiodarone** is a medication commonly used to treat arrhythmias, but it can have significant effects on thyroid function. It can lead to both **drug-induced hypothyroidism** and drug-induced hyperthyroidism, depending on the patient's individual response. In this case, tiredness, sensitivity to cold, weight gain, and constipation are indicative of hypothyroidism.\r\n\r\n***\r\n\r\nClassic signs and symptoms of hypothyroidism, which include fatigue, sensitivity to cold, weight gain, and constipation, are not consistent with hyperthyroidism or other thyroid-related conditions like Graves disease or goiter.","reference":"Karen Whalen, et al. Lippincott Illustrated Reviews: Pharmacology. 7th ed., Lippincott Williams \u0026 Wilkins, 2019: 255.","responses":[{"text":"Goiter","correct":false,"visible":false},{"text":"Cardiotoxicity","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Drug-induced hypothyroidism","correct":true,"visible":false},{"text":"Drug-induced hyperthyroidism","correct":false,"visible":false}]},{"id":21905,"text":"A patient presents with the complaint that he gets dizzy and experiences blurred vision and fatigue within three minutes of standing up from a supine position. He is confirmed to have orthostatic hypotension. Physical examination reveals hyperpigmentation of palmar creases, nipples, and axillary region. Lab investigations reveal fasting hypoglycemia and hyponatremia. Which of the following can be given to manage this patient?","explanation":"Orthostatic hypotension along with hyperpigmentation of palmar creases, nipples, and axillary regions are suggestive of **Addison disease**, also known as primary adrenal insufficiency.\r\n\r\nThe patient needs **mineralocorticoid** replacement to correct the **hyponatremia** and manage electrolyte imbalances. Additionally, **glucocorticoid** replacement is necessary to address **hypoglycemia** and provide cortisol replacement, which is vital for managing stress and maintaining blood glucose levels.\r\n\r\n***\r\n\r\nWhile frequent meals can help stabilize blood sugar levels in some conditions, this approach does not address the underlying cause of Addison disease, which is adrenal insufficiency. It is crucial to provide appropriate hormone replacement therapy.\r\n\r\nAndrogen replacement is not the primary treatment for Addison disease. This condition primarily involves cortisol and aldosterone deficiency, so hormone replacement should focus on these deficiencies.\r\n\r\nThere is no indication of a pancreatic tumor in this case, so surgery is not warranted.\r\n\r\nSpironolactone and eplerenone are aldosterone antagonists and would not be suitable for treating primary adrenal insufficiency. In fact, they could exacerbate the electrolyte imbalances in this patient.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 673.","responses":[{"text":"Androgen replacement with DHEAS (50 mg/day)","correct":false,"visible":false},{"text":"Spironolactone and eplerenone","correct":false,"visible":false},{"text":"Mineralocorticoid and glucocorticoids","correct":true,"visible":false},{"text":"Surgery to remove pancreatic tumor","correct":false,"visible":false},{"text":"Many small meals to overcome hypoglycemia","correct":false,"visible":false}]},{"id":21906,"text":"A patient having hypertension, hyperglycemia, and truncal obesity is diagnosed as a case of Cushing syndrome following a dexamethasone test. What is the most likely cause of hypercortisolism if serum ACTH is below normal?","explanation":"**Adrenal adenoma** is a benign tumor of the adrenal gland that produces **excess cortisol**. This cortisol production is autonomous and does not depend on ACTH stimulation. Therefore, the serum ACTH levels are typically low due to negative feedback inhibition.\r\n\r\n***\r\n\r\nChronic alcohol use can lead to hypercortisolism, but it typically does not suppress ACTH levels. Moreover, it is less likely to produce a distinct clinical picture of Cushing syndrome as described in the patient.\r\n\r\nSmall cell lung carcinoma can lead to ectopic ACTH syndrome, resulting in Cushing syndrome. However, in ectopic ACTH syndrome, ACTH levels are usually elevated, not decreased as in the patient’s case.\r\n\r\nPituitary adenoma is a common cause of Cushing disease. In this condition, an adenoma in the pituitary gland secretes excess ACTH, leading to increased cortisol levels.\r\n\r\nEctopic ACTH syndrome involves non-pituitary tumors secreting ACTH, leading to Cushing syndrome. Similar to small cell lung carcinoma, this would typically present with elevated ACTH levels, not decreased ones.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 668.","responses":[{"text":"Adrenal adenoma","correct":true,"visible":false},{"text":"Hypercortisolism due to excess alcohol","correct":false,"visible":false},{"text":"Small cell lung carcinoma","correct":false,"visible":false},{"text":"Ectopic ACTH Syndrome","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false}]},{"id":21907,"text":"A young female presented with fever, palpitations, increased sweating, and weight loss. On examination, she has tachycardia and mild painful swelling in the neck. What is your clinical impression if thyroid scintigraphy shows low uptake thyrotoxicosis?","explanation":"**Transient thyroiditis** is characterized by a phase of thyrotoxicosis, which can be followed by hypothyroidism before eventually returning to a euthyroid state. The key features in this case—fever, tachycardia, painful neck swelling—align with thyroiditis. Importantly, the **low uptake of thyroid scintigraphy** is a distinguishing feature of transient thyroiditis.\r\n***\r\n\r\nToxic adenoma presents with symptoms of hyperthyroidism due to a single functioning thyroid nodule. However, thyroid scintigraphy would show increased uptake in the nodule with suppressed uptake in the rest of the thyroid, which is not the case here.\r\n\r\nSimilar to toxic adenoma, toxic multinodular goiter would show areas of increased uptake corresponding to the nodules. The rest of the thyroid would have suppressed uptake.\r\n\r\nGraves disease is the most common cause of hyperthyroidism and would present with symptoms similar to those described. However, thyroid scintigraphy would show diffusely increased uptake throughout the thyroid gland.\r\n\r\nWhile the patient does exhibit symptoms of hyperthyroidism, it does not specifically address the low uptake seen in scintigraphy, which is crucial for accurate diagnosis.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 638.","responses":[{"text":"Toxic multinodular goiter","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Transient thyroiditis","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Toxic adenoma","correct":false,"visible":false}]},{"id":21908,"text":"Patients presented to the outpatient department with low blood pressure of  90/60 mmHg, hyponatremia, and hyperkalemia. Which of the following is directly or indirectly responsible for this condition?","explanation":"The adrenal cortex has three distinct zones: zona glomerulosa, zona fasciculata, and zona reticularis. Each zone secretes different hormones. The zona glomerulosa is responsible for the production of mineralocorticoids, primarily aldosterone. Aldosterone plays a crucial role in regulating sodium and potassium levels and blood pressure.\r\n\r\n**Hyposecretion of zona glomerulosa** results in **decreased aldosterone** production, leading to decreased sodium reabsorption in the kidneys and increased potassium retention. This leads to **hyponatremia** and **hyperkalemia**, contributing to low blood pressure due to the loss of sodium and the effects of elevated potassium levels.\r\n\r\n***\r\n\r\nHyposecretion of zona reticularis and Hypersecretion of zona reticularis are not directly associated with the regulation of sodium, potassium, or blood pressure.\r\n\r\nHypersecretion of zona glomerulosa would lead to excess aldosterone production, which could cause hypernatremia (high sodium levels) and hypokalemia (low potassium levels), but not the symptoms described in the question.\r\n\r\nHyposecretion of zona fasciculata is related to the production of glucocorticoids, not mineralocorticoids, and would not directly lead to the electrolyte imbalances described.","reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 666.","responses":[{"text":"Hyposecretion of zona fasciculata","correct":false,"visible":false},{"text":"Hypersecretion of zona glomerulosa","correct":false,"visible":false},{"text":"Hyposecretion of zona reticularis","correct":false,"visible":false},{"text":"Hyposecretion of zona glomerulosa","correct":true,"visible":false},{"text":"Hypersecretion of zona reticularis","correct":false,"visible":false}]},{"id":21909,"text":"Growth hormone which is used for therapeutic purposes is derived from which of the following sources?","explanation":"**Recombinant DNA technology** allows the production of human **growth hormone** (hGH) by inserting the gene responsible for its production into bacteria or yeast cells. These cells then produce synthetic human growth hormone, which is used for therapeutic purposes.\r\n\r\n***\r\n\r\nGrowth hormone from horses, purified growth hormone from rabbits, and cadaveric pituitaries are not commonly used sources for therapeutic growth hormone due to potential issues with purity, safety, and compatibility with human recipients.\r\n\r\nPorcine pituitaries have been used in the past, but recombinant technology has largely replaced this source because of the risk of transmission of animal diseases and concerns about compatibility.","reference":"Takeda, A., et al. “Recombinant Human Growth Hormone for the Treatment of Growth Disorders in Children: A Systematic Review and Economic Evaluation.” NIHR Health Technology Assessment Programme: Executive Summaries, NIHR Journals Library, 2010. www.ncbi.nlm.nih.gov, https://www.ncbi.nlm.nih.gov/books/NBK56794/.","responses":[{"text":"Cadaveric pituitaries","correct":false,"visible":false},{"text":"Recombinant DNA techonology","correct":true,"visible":false},{"text":"Purified growth hormone from rabbits","correct":false,"visible":false},{"text":"Growth hormone from horses","correct":false,"visible":false},{"text":"Porcine pituitaries","correct":false,"visible":false}]},{"id":21910,"text":"Which of the following can be used to check the linearity of data in the SPSS software?","explanation":"A **scatter plot** is a graphical representation used to visualize the relationship between two continuous variables. It helps **assess** whether the data points form a **linear pattern**, which indicates a linear relationship between the variables.\r\n\r\n***\r\n\r\nBar charts, box plots, pie charts, and histograms are graphical representations primarily used for categorical or discrete data and are not suitable for assessing linearity between continuous variables.","reference":"Creating a Scatterplot Using SPSS Statistics - Setting up the Scatterplot, Formatting the Plot and Outputting the Plot | Laerd Statistics. https://statistics.laerd.com/spss-tutorials/scatterplot-using-spss-statistics.php#. Accessed 25 Dec. 2023.","responses":[{"text":"Histogram","correct":false,"visible":false},{"text":"Box plot","correct":false,"visible":false},{"text":"Pie charts","correct":false,"visible":false},{"text":"Scatter plot","correct":true,"visible":false},{"text":"Bar charts","correct":false,"visible":false}]},{"id":21912,"text":"A patient with hyperparathyroidism develops urinary calculi. What will be the treatment of hyperparathyroidism in this patient?","explanation":"A **parathyroidectomy** involves the surgical removal of one or more hyperactive parathyroid glands. This procedure aims to correct the excessive parathyroid hormone (PTH) production and normalize calcium levels in the body, effectively preventing the recurrence of kidney stones and managing the underlying **hyperparathyroidism**.\r\n\r\nHyperparathyroidism is characterized by excessive secretion of PTH, leading to elevated calcium levels in the blood (hypercalcemia) and contributing to kidney stone formation (**urinary calculi**) due to increased urinary calcium.\r\n\r\n\r\n***\r\n\r\nAntithyroid drugs are used to treat hyperthyroidism, not hyperparathyroidism.\r\n\r\nCalcium blockers are used to treat hypertension and certain heart conditions, unrelated to hyperparathyroidism.\r\n\r\nCalcium supplements can exacerbate the condition by increasing serum calcium levels.\r\n\r\nIodine is used in thyroid disorders but is not a standard treatment for hyperparathyroidism.","reference":"(1) O’Connell PR, McCaskie AW, Sayers RD, eds. Bailey \u0026 Love’s Short Practice of Surgery. 28th ed. CRC Press, Taylor \u0026 Francis Group; 2023: 879.\r\n(2) Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 664.","responses":[{"text":"Parathyroidectomy","correct":true,"visible":false},{"text":"Antithyroid drugs","correct":false,"visible":false},{"text":"Calcium supplements","correct":false,"visible":false},{"text":"Calcium blockers","correct":false,"visible":false},{"text":"Iodine","correct":false,"visible":false}]},{"id":21915,"text":"Which of the following tests determines the difference between the observed and expected data for a group?","explanation":"**Chi-square test** is used to determine if there is a significant association between two categorical variables, comparing the **observed data** to the **expected data** under the assumption of independence. It's often used to analyze data in a contingency table, assessing whether there is a difference between the observed and expected frequencies.\r\n\r\n***\r\n\r\nT-test and analysis of variance (ANOVA) are used for comparing means between two or more groups. These tests do not directly deal with observed versus expected data differences in a categorical context.\r\n\r\nMultivariate analysis of variance (MANOVA) is used to compare multiple dependent variables between multiple groups.\r\n\r\nRegression is used to analyze the relationship between a dependent variable and one or more independent variables.","reference":"(1)  The chi-squared tests | The BMJ. The BMJ | The BMJ: leading general medical journal. Research. Education. Comment. Published October 28, 2020. Accessed December 25, 2023. https://www.bmj.com/about-bmj/resources-readers/publications/statistics-square-one/8-chi-squared-tests\r\n\r\n(2) “What Is a Chi-Square Test? Formula, Examples \u0026 Uses | Simplilearn.” Simplilearn.Com, https://www.simplilearn.com/tutorials/statistics-tutorial/chi-square-test. Accessed 25 Dec. 2023.","responses":[{"text":"Chi square test","correct":true,"visible":false},{"text":"MANOVA","correct":false,"visible":false},{"text":"ANOVA","correct":false,"visible":false},{"text":"T-test","correct":false,"visible":false},{"text":"Regression","correct":false,"visible":false}]},{"id":21919,"text":"You have to counsel a diabetic patient about regular checking of his foot. Which of the following is the best statement for the patient?","explanation":null,"reference":"Hirpha, Namo, et al. “Diabetic Foot Self-Care Practices Among Adult Diabetic Patients: A Descriptive Cross-Sectional Study.” Diabetes, Metabolic Syndrome and Obesity: Targets and Therapy, 4 Dec. 2020, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7723031/.","responses":[{"text":"You should do it because regular foot examinations with optimal glycemic control can prevent foot ulceration","correct":true,"visible":false},{"text":"You have to check daily if the foot hurts","correct":false,"visible":false},{"text":"Get your foot checked if you find it ischemic or gangrenic","correct":false,"visible":false},{"text":"You just have to do it","correct":false,"visible":false},{"text":"You should do it otherwise you will get an amputation","correct":false,"visible":false}]},{"id":21922,"text":"Which of the following tests can determine the difference in distribution between two or more categorical variables?","explanation":null,"reference":"Hazra, Avijit, and Nithya Gogtay. “Biostatistics Series Module 4: Comparing Groups – Categorical Variables.” Indian Journal of Dermatology, 2016, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4966396/.","responses":[{"text":"MANOVA","correct":false,"visible":false},{"text":"Pearson's χ2 test","correct":true,"visible":false},{"text":"Z test","correct":false,"visible":false},{"text":"T test","correct":false,"visible":false},{"text":"ANOVA","correct":false,"visible":false}]},{"id":21925,"text":"A researcher wants to find out the difference in the intensity of stress between three groups of factory workers. The variables being used are continuous. Which of the following tests can be used in this case?","explanation":null,"reference":"“ANOVA Test: Definition \u0026 Uses (Updated 2023).” Qualtrics, https://www.qualtrics.com/experience-management/research/anova/. Accessed 25 Dec. 2023.","responses":[{"text":"T-test","correct":false,"visible":false},{"text":"Regression","correct":false,"visible":false},{"text":"MANOVA","correct":false,"visible":false},{"text":"ANOVA","correct":true,"visible":false},{"text":"Chi-Square","correct":false,"visible":false}]},{"id":21939,"text":"A 35-year-old lady presented to the outpatient department with the complaint of an increase in appetite, weight loss, and sweating for the past 3 months. She has a gritty sensation in her eyes. On examination, her hands are moist and warm. The thyroid gland is palpable with a bruit. Which of the following is not a treatment option in this case?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 644.","responses":[{"text":"Antithyroid drugs","correct":false,"visible":false},{"text":"Steroids","correct":true,"visible":false},{"text":"Beta-blockers","correct":false,"visible":false},{"text":"Thyroidectomy","correct":false,"visible":false},{"text":"Radioactive iodine","correct":false,"visible":false}]},{"id":21949,"text":"A person presented to the outpatient department with hypertension, hypernatremia, and hypokalemia. His BUN was 26 mg/dl and serum creatinine was 1.3 mg/dl. What can be the possible cause of these presentations if Cushing's syndrome is ruled out?","explanation":null,"reference":"Balhana, Sílvia, et al. “Conn’s Syndrome: An Unusual Cause of Periodic Paralysis.” Cureus, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9180667/. Accessed 25 Dec. 2023.","responses":[{"text":"Chronic renal failure","correct":false,"visible":false},{"text":"Adrenal hyperplasia","correct":false,"visible":false},{"text":"Adrenal atrophy","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Conn's syndrome","correct":true,"visible":false}]},{"id":21950,"text":"A child presents to the emergency department with complaints of vomiting, seizures, and respiratory distress after having eaten a sausage. Upon physical examination, there is a descending symmetric flaccid paralysis of voluntary muscles and loss of deep tendon reflexes. Which of the following can be the cause of these symptoms?","explanation":null,"reference":"Tiwari, Aman, and Shivaraj Nagalli. “Clostridium Botulinum Infection.” StatPearls, StatPearls Publishing, 2023. PubMed, http://www.ncbi.nlm.nih.gov/books/NBK553081/.","responses":[{"text":"Clostridium welchi","correct":false,"visible":false},{"text":"Clostridium botulinum","correct":true,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Salmonella typhi","correct":false,"visible":false},{"text":"Bacillus cereus","correct":false,"visible":false}]},{"id":21951,"text":"Which of the following tests can be done to investigate a radiologically suspicious solitary cervical nodule of 2 cm that moves with deglutition?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 643.","responses":[{"text":"X-ray","correct":false,"visible":false},{"text":"Serum IgG levels","correct":false,"visible":false},{"text":"Fine needle aspiration","correct":true,"visible":false},{"text":"CT-scan","correct":false,"visible":false},{"text":"Serum TSH levels","correct":false,"visible":false}]},{"id":21952,"text":"Metformin can not be given to a diabetic patient with an addiction to alcohol as it will increase the chances of which of the following?","explanation":null,"reference":"Karen Whalen, et al. Lippincott Illustrated Reviews: Pharmacology. 7th ed., Lippincott Williams \u0026 Wilkins, 2019: 319.","responses":[{"text":"Severe hepatoxicity","correct":false,"visible":false},{"text":"Pancreatic failure","correct":false,"visible":false},{"text":"Adrenal insufficiency","correct":false,"visible":false},{"text":"Lactic acidosis","correct":true,"visible":false},{"text":"Gastric disturbances","correct":false,"visible":false}]},{"id":21953,"text":"Which of the following is the class of insulin receptors?","explanation":null,"reference":"Insulin Receptor - an Overview | ScienceDirect Topics. https://www.sciencedirect.com/topics/agricultural-and-biological-sciences/insulin-receptor#:~:text=The%20insulin%20receptor%20(IR)%20is,family%20of%20Tyrosine%20Kinase%20receptors. Accessed 25 Dec. 2023","responses":[{"text":"Ionic receptor","correct":false,"visible":false},{"text":"Covalent receptor","correct":false,"visible":false},{"text":"Tyrosine kinase","correct":true,"visible":false},{"text":"Mixed receptor","correct":false,"visible":false},{"text":"G protein coupled receptor","correct":false,"visible":false}]}
]

